export const DocumentService = {
  getAll: async (): Promise<Document[]> => {
    const q = query(collection(db, "documents"), orderBy("updatedAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Document) : null;
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any, existingId?: string): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;
    const version = initialVersion || '0.0';
    const info = determineStateFromVersion(version);
    const progress = initialProgress !== undefined ? initialProgress : info.progress;

    if (existingId) {
        // LÓGICA DE ACTUALIZACIÓN (Mismo ID, historia unificada)
        const docRef = doc(db, "documents", existingId);
        const oldSnap = await getDoc(docRef);
        const oldData = oldSnap.data() as Document;

        const updateData: Partial<Document> = {
            state,
            version,
            progress,
            description,
            hasPendingRequest: isSubmission,
            updatedAt: new Date().toISOString()
        };

        await updateDoc(docRef, updateData);
        await HistoryService.log(existingId, author, 'Nueva Versión (Carga)', oldData.state, state, `Carga de archivo versión ${version}`, version);

        return { id: existingId, ...oldData, ...updateData } as Document;
    } else {
        // LÓGICA DE CREACIÓN NUEVA
        let uploadedFiles: DocFile[] = [];
        const mergedAssignees = Array.from(new Set([...(hierarchy?.assignees || []), author.id]));

        const newDocData: Omit<Document, 'id'> = {
          title, description, authorId: author.id, authorName: author.name, assignedTo: author.id, assignees: mergedAssignees, state, version, progress, hasPendingRequest: isSubmission, files: uploadedFiles, createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
        };
        const docRef = await addDoc(collection(db, "documents"), newDocData);

        await HistoryService.log(docRef.id, author, 'Creación', DocState.NOT_STARTED, state, `Iniciado Versión ${version}`, version);

        const allUsers = await UserService.getAll();
        const coordinators = allUsers.filter(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);
        coordinators.forEach(coord => {
            NotificationService.create(
                coord.id,
                docRef.id,
                'ASSIGNMENT',
                'Nueva Solicitud de Documento',
                `El analista ${author.name} ha iniciado: ${title}`,
                author.name
            );
        });

        return { id: docRef.id, ...newDocData } as Document;
    }
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "documents", id)); },
  transitionState: async (docId: string, user: User, action: any, comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Documento no encontrado");
      const currentDoc = docSnap.data() as Document;
      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;

      const actionLabels: Record<string, string> = {
          'APPROVE': 'Aprobación',
          'REJECT': 'Rechazo',
          'COMMENT': 'Observación',
          'REQUEST_APPROVAL': 'Solicitud de Revisión',
          'ADVANCE': 'Avance de Flujo'
      };

      const displayAction = actionLabels[action] || action;

      if (customVersion) {
        newVersion = customVersion;
        const info = determineStateFromVersion(customVersion);
        newState = info.state;
      }

      if (action === 'APPROVE') hasPending = false;
      else if (action === 'REJECT') { 
          hasPending = false; 
          newState = determineStateFromVersion(newVersion).state; 
      }
      else if (action === 'REQUEST_APPROVAL') hasPending = true;

      // ACTUALIZACIÓN DE PROGRESO: Aseguramos que se guarde el porcentaje correcto en la BD
      const { progress: newProgress } = determineStateFromVersion(newVersion);

      await updateDoc(docRef, { 
          state: newState, 
          version: newVersion, 
          progress: newProgress,
          hasPendingRequest: hasPending, 
          updatedAt: new Date().toISOString() 
      });

      await HistoryService.log(docId, user, displayAction, currentDoc.state, newState, comment, newVersion);

      const allUsers = await UserService.getAll();

      if (action === 'APPROVE' || action === 'REJECT') {
          const notificationType = action === 'APPROVE' ? 'APPROVAL' : 'REJECTION';
          const title = action === 'APPROVE' ? 'Documento Aprobado' : 'Documento Rechazado';
          const msg = `El documento "${currentDoc.title}" ha sido ${action === 'APPROVE' ? 'aprobado' : 'rechazado'} (Versión ${newVersion}).`;

          currentDoc.assignees.forEach(aid => {
              if (aid !== user.id) {
                NotificationService.create(aid, docId, notificationType, title, msg, user.name);
              }
          });

          if (!currentDoc.assignees.includes(currentDoc.authorId) && currentDoc.authorId !== user.id) {
              NotificationService.create(currentDoc.authorId, docId, notificationType, title, msg, user.name);
          }
      } 
      else if (action === 'COMMENT') {
          const msg = `Nueva observación en "${currentDoc.title}": ${comment.substring(0, 50)}...`;
          const targets = new Set([...(currentDoc.assignees || []), currentDoc.authorId]);
          targets.forEach(aid => {
              if (aid !== user.id) {
                NotificationService.create(aid, docId, 'COMMENT', 'Nueva Observación', msg, user.name);
              }
          });
      } 
      else if (customVersion) {
          const reviewStates = [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW];
          if (reviewStates.includes(newState)) {
              const coordinators = allUsers.filter(u => u.role === UserRole.COORDINATOR || u.role === UserRole.ADMIN);
              const estadoNombre = STATE_CONFIG[newState]?.label.split('(')[0].trim();
              coordinators.forEach(coord => {
                  if (coord.id !== user.id) {
                    NotificationService.create(
                        coord.id,
                        docId,
                        'ASSIGNMENT',
                        'Revisión Solicitada',
                        `Nueva versión en ${estadoNombre}: ${currentDoc.title} (${newVersion})`,
                        user.name
                    );
                  }
              });
          }
      }
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const proj = data.project;
      const macro = data.macroprocess || 'Sin Macroproceso';
      const process = data.process;
      const node: ProcessNode = { name: data.name, docId: doc.id, assignees: data.assignees || [], referentIds: data.referentIds || [], requiredTypes: data.requiredTypes || [], active: data.active !== false };
      if (!hierarchy[proj]) hierarchy[proj] = {};
      if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
      if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
      hierarchy[proj][macro][process].push(node);
    });
    return hierarchy;
  },
  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};
      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (data.active === false) return;
          const proj = data.project;
          const macro = data.macroprocess || 'Sin Macroproceso';
          const process = data.process;
          if (!hierarchy[proj]) hierarchy[proj] = {};
          if (!hierarchy[proj][macro]) hierarchy[proj][macro] = {};
          if (!hierarchy[proj][macro][process]) hierarchy[proj][macro][process] = [];
          hierarchy[proj][macro][process].push(data.name);
      });
      return hierarchy;
  },
  updateMatrixAssignment: async (docId: string, assignees: string[]) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { assignees });
  },
  updateReferentLinks: async (referentId: string, selectedDocIds: string[]) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);

      snapshot.docs.forEach(d => {
          const data = d.data();
          let referents = data.referentIds || [];
          const isSelected = selectedDocIds.includes(d.id);
          const hasReferent = referents.includes(referentId);

          if (isSelected && !hasReferent) {
              batch.update(d.ref, { referentIds: [...referents, referentId] });
          } else if (!isSelected && hasReferent) {
              batch.update(d.ref, { referentIds: referents.filter((id:string) => id !== referentId) });
          }
      });
      await batch.commit();
  },
  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const current = new Set(snap.data().requiredTypes || []);
          if (current.has(type)) current.delete(type); else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },
  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      await setDoc(doc(db, "process_matrix", id), { project, macroprocess: macro, process, name, assignees, referentIds: [], requiredTypes, active: true });
  },
  deleteMicroprocess: async (docId: string) => { await deleteDoc(doc(db, "process_matrix", docId)); },
  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(d => {
          const data = d.data();
          const key = `${normalizeHeader(data.project)}|${normalizeHeader(data.name)}`;
          map[key] = data.requiredTypes || [];
      });
      return map;
  },
  toggleProcessStatus: async (docId: string, currentStatus: boolean) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, { active: !currentStatus });
  },
  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", name));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      }

      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },
  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string, newName: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') {
          q = query(collection(db, "process_matrix"), where("project", "==", oldName));
      } else if (level === 'MACRO') {
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
      } else { // PROCESS
          q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));
      }
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          const update: any = {};
          if (level === 'PROJECT') update.project = newName;
          else if (level === 'MACRO') update.macroprocess = newName;
          else update.process = newName;
          batch.update(d.ref, update);
      });
      await batch.commit();
  },
  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      const ref = doc(db, "process_matrix", docId);
      await updateDoc(ref, {
          project: targetProject,
          macroprocess: targetMacro,
          process: targetProcess
      });
  },
  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS'); if (fce) requiredTypes.push('FCE'); if (pm) requiredTypes.push('PM'); if (tobe) requiredTypes.push('TO BE');
           const id = generateMatrixId(project, micro);
           batch.set(doc(db, "process_matrix", id), { project, macroprocess: 'Macroproceso General', process: 'Proceso General', name: micro, assignees: [], referentIds: [], requiredTypes, active: true });
      }
      await batch.commit();
  }
};

export const DatabaseService = {
    exportData: async (): Promise<string> => {
        const collections = ['users', 'documents', 'history', 'process_matrix', 'notifications', 'referents'];
        const data: any = {};
        for (const colName of collections) {
            const snapshot = await getDocs(collection(db, colName));
            data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
        }
        return JSON.stringify(data, null, 2);
    },
    importData: async (jsonString: string) => {
        const data = JSON.parse(jsonString);
        for (const colName of Object.keys(data)) {
            await deleteCollectionInBatches(colName);
            const items = data[colName];
            let batch = writeBatch(db);
            let count = 0;
            for (const item of items) {
                const { _id, ...docData } = item;
                batch.set(doc(db, colName, _id), docData);
                count++;
                if (count >= 400) { await batch.commit(); batch = writeBatch(db); count = 0; }
            }
            if (count > 0) await batch.commit();
        }
    },
    fullSystemResetAndImport: async (rulesCSV: string, historyCSV: string, onProgress: (percent: number, status: string) => void): Promise<{ created: number, historyMatched: number }> => {
        onProgress(5, "Limpiando...");
        await deleteCollectionInBatches("documents"); await deleteCollectionInBatches("history"); await deleteCollectionInBatches("process_matrix"); await deleteCollectionInBatches("notifications");
        onProgress(10, "Reglas...");
        const rows = rulesCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
        const headers = rows[0].split(/[;,]/).map(h => normalizeHeader(h));
        const idxProject = headers.findIndex(h => h.includes('PROYECTO'));
        const idxMacro = headers.findIndex(h => h.includes('MACRO'));
        const idxProcess = headers.findIndex(h => h === 'PROCESO');
        const idxMicro = headers.findIndex(h => h.includes('MICRO'));
        const idxAnalyst = headers.findIndex(h => h.includes('ANALISTA') || h.includes('RESPONSABLE'));
        const idxAsis = headers.findIndex(h => h.includes('ASIS') || h.includes('AS IS'));
        const idxFce = headers.findIndex(h => h.includes('FCE'));
        const idxPm = headers.findIndex(h => h.includes('PM'));
        const idxTobe = headers.findIndex(h => h.includes('TOBE') || h.includes('TO BE'));
        const allUsers = await UserService.getAll();
        let createdCount = 0;
        let batch = writeBatch(db);
        let opCount = 0;
        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(/[;,]/).map(c => c.trim());
            if (cols.length < 3) continue;
            const project = cols[idxProject] || 'GENERAL';
            const macro = cols[idxMacro] || 'General';
            const process = cols[idxProcess] || 'General';
            const micro = cols[idxMicro];
            if (!micro) continue;
            const assignees = findUserIdsFromCSV(allUsers, cols[idxAnalyst]);
            const requiredTypes: string[] = [];
            if (cols[idxAsis] === '1') requiredTypes.push('AS IS');
            if (cols[idxFce] === '1') requiredTypes.push('FCE');
            if (cols[idxPm] === '1') requiredTypes.push('PM');
            if (cols[idxTobe] === '1') requiredTypes.push('TO BE');
            const id = generateMatrixId(project, micro);
            const nodeData = { project, macroprocess: macro, process, name: micro, assignees, referentIds: [], requiredTypes, active: true };
            batch.set(doc(db, "process_matrix", id), nodeData);
            opCount++; createdCount++;
            if (opCount >= 400) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        onProgress(100, "Finalizando...");
        return { created: createdCount, historyMatched: 0 };
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy, UserRole, Document, FullHierarchy } from '../types';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, AlertTriangle, Info, Layers, FileType, FilePlus, ListFilter, Lock, RefreshCw, History } from 'lucide-react';

interface Props {
  user: User;
}

// Request Types mapped to Parser Logic
type RequestType = 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL';

// Map States to Levels for filtering
const STATE_LEVELS: Record<DocState, number> = {
    [DocState.NOT_STARTED]: 0,
    [DocState.INITIATED]: 1,
    [DocState.IN_PROCESS]: 2,
    [DocState.INTERNAL_REVIEW]: 3,
    [DocState.SENT_TO_REFERENT]: 4,
    [DocState.REFERENT_REVIEW]: 4,
    [DocState.SENT_TO_CONTROL]: 5,
    [DocState.CONTROL_REVIEW]: 5,
    [DocState.APPROVED]: 6,
    [DocState.REJECTED]: 0 // Special case
};

const REQUEST_TYPE_LEVELS: Record<RequestType, number> = {
    'INITIATED': 1,
    'IN_PROCESS': 2,
    'INTERNAL': 3,
    'REFERENT': 4,
    'CONTROL': 5
};

const CreateDocument: React.FC<Props> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Hook to access passed state
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);

  // Hierarchy Selection State with Strict Typing
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [fullHierarchyCache, setFullHierarchyCache] = useState<FullHierarchy>({}); // Cache full hierarchy for assignments

  // Matrix Requirement Map (Project|Micro -> AllowedTypes[])
  const [requirementsMap, setRequirementsMap] = useState<Record<string, DocType[]>>({});

  const [selectedProject, setSelectedProject] = useState<string>('');
  const [selectedMacro, setSelectedMacro] = useState<string>('');
  const [selectedProcess, setSelectedProcess] = useState<string>('');
  const [selectedMicro, setSelectedMicro] = useState<string>('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');

  // New: Request Type for Safety
  const [requestType, setRequestType] = useState<RequestType | ''>('');

  // Existing Document State (for filtering)
  const [existingDoc, setExistingDoc] = useState<Document | null>(null);
  const [existingDocLevel, setExistingDocLevel] = useState<number>(0);

  // File Upload State
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Inferred Workflow State
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedProgress, setDetectedProgress] = useState(10);

  // Cache of all docs for quick lookup
  const [allDocsCache, setAllDocsCache] = useState<Document[]>([]);

  useEffect(() => {
      loadData();
  }, []);

  // Effect to find existing document when selection changes
  useEffect(() => {
      if (selectedProject && selectedMicro && selectedDocType) {
          const found = allDocsCache.find(d => 
              normalizeHeader(d.project || '') === normalizeHeader(selectedProject) && 
              normalizeHeader(d.microprocess || d.title.split(' - ')[0] || '') === normalizeHeader(selectedMicro) &&
              d.docType === selectedDocType
          );

          if (found) {
              setExistingDoc(found);
              const level = STATE_LEVELS[found.state] || 0;
              setExistingDocLevel(level);
          } else {
              setExistingDoc(null);
              setExistingDocLevel(0);
          }
      } else {
          setExistingDoc(null);
          setExistingDocLevel(0);
      }

      setRequestType('');
      resetFile();

  }, [selectedProject, selectedMicro, selectedDocType, allDocsCache]);

  const loadData = async () => {
      try {
          const [reqMap, full, docs] = await Promise.all([
              HierarchyService.getRequiredTypesMap(),
              HierarchyService.getFullHierarchy(),
              DocumentService.getAll()
          ]);

          setRequirementsMap(reqMap);
          setAllDocsCache(docs);
          setFullHierarchyCache(full);

          if (user.role === UserRole.ADMIN) {
               const adminTree: UserHierarchy = {};
               Object.keys(full).forEach(p => {
                   adminTree[p] = {};
                   Object.keys(full[p]).forEach(m => {
                       adminTree[p][m] = {};
                       Object.keys(full[p][m]).forEach(proc => {
                           adminTree[p][m][proc] = full[p][m][proc].map(n => n.name);
                       });
                   });
               });
               setUserHierarchy(adminTree);
          } else {
              const userH = await HierarchyService.getUserHierarchy(user.id);
              setUserHierarchy(userH);
          }

          if (location.state?.prefill) {
              const { project, macro, process, micro, docType } = location.state.prefill;
              if (project) setSelectedProject(project);
              if (macro) setSelectedMacro(macro);
              if (process) setSelectedProcess(process);
              if (micro) setSelectedMicro(micro);

              if (docType && project && micro) {
                  const key = `${normalizeHeader(project)}|${normalizeHeader(micro)}`;
                  const allowed = reqMap[key] || [];
                  if (allowed.includes(docType)) {
                      setSelectedDocType(docType);
                  }
              }
          }
      } catch (e) {
          console.error("Error loading create document data", e);
      } finally {
          setInitializing(false);
      }
  };

  const getProjects = (): string[] => Object.keys(userHierarchy);
  const getMacros = (): string[] => (!selectedProject || !userHierarchy[selectedProject]) ? [] : Object.keys(userHierarchy[selectedProject]);
  const getProcesses = (): string[] => (!selectedProject || !selectedMacro || !userHierarchy[selectedProject]?.[selectedMacro]) ? [] : Object.keys(userHierarchy[selectedProject][selectedMacro]);
  const getMicros = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess) return [];
      const processes = userHierarchy[selectedProject]?.[selectedMacro];
      if (!processes) return [];
      return processes[selectedProcess] || [];
  };

  const getAllowedDocTypes = (): DocType[] => {
      if (!selectedProject || !selectedMicro) return [];
      const key = `${normalizeHeader(selectedProject)}|${normalizeHeader(selectedMicro)}`;
      return requirementsMap[key] || [];
  };

  const getAssigneesForSelection = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess || !selectedMicro) return [];
      const nodes = fullHierarchyCache[selectedProject]?.[selectedMacro]?.[selectedProcess] || [];
      const node = nodes.find(n => n.name === selectedMicro);
      return node?.assignees || [];
  };

  const handleProjectChange = (val: string) => {
      setSelectedProject(val); setSelectedMacro(''); setSelectedProcess(''); setSelectedMicro(''); resetFile();
  };

  const handleMacroChange = (val: string) => {
      setSelectedMacro(val); setSelectedProcess(''); setSelectedMicro(''); resetFile();
  };

  const handleProcessChange = (val: string) => {
      setSelectedProcess(val); setSelectedMicro(''); resetFile();
  };

  const handleMicroChange = (val: string) => {
      setSelectedMicro(val); setSelectedDocType(''); resetFile();
  }

  const handleTypeChange = (val: string) => {
      setSelectedDocType(val as DocType); resetFile();
  }

  const handleRequestTypeChange = (val: string) => {
      setRequestType(val as RequestType); resetFile();
  }

  const resetFile = () => {
      setFile(undefined); setFileError([]); setIsFileValid(false); setTitle(''); setDescription('');
      if (fileInputRef.current) { fileInputRef.current.value = ''; }
  };

  const mapParserStateToEnum = (parserState: string): DocState => {
      switch (parserState) {
          case 'Iniciado': return DocState.INITIATED;
          case 'En Proceso': return DocState.IN_PROCESS;
          case 'En revisión interna': return DocState.INTERNAL_REVIEW;
          case 'Enviado a Referente': return DocState.SENT_TO_REFERENT;
          case 'Revisión Interna Referente': return DocState.REFERENT_REVIEW;
          case 'Enviado a Control de Gestión': return DocState.SENT_TO_CONTROL;
          case 'Revisión Interna Control': return DocState.CONTROL_REVIEW;
          case 'Aprobado': return DocState.APPROVED;
          default: return DocState.INITIATED;
      }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const selectedFile = e.target.files[0];
          setFile(selectedFile);

          const result = parseDocumentFilename(
              selectedFile.name,
              selectedProject,
              selectedMicro,
              selectedDocType || undefined,
              requestType || undefined
          );

          if (result.valido) {
              setIsFileValid(true);
              setFileError([]);
              const cleanMicro = result.microproceso || selectedMicro;
              const cleanType = result.tipo || selectedDocType;
              setTitle(`${cleanMicro} - ${cleanType}`);
              setDescription(`Carga de documento: ${cleanType} (${result.nomenclatura})`);
              if (result.estado) setDetectedState(mapParserStateToEnum(result.estado));
              if (result.nomenclatura) setDetectedVersion(result.nomenclatura);
              if (result.porcentaje) setDetectedProgress(result.porcentaje);
          } else {
              setIsFileValid(false);
              setFileError(result.errores);
              setTitle('');
              setDescription('');
          }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !description || !file || !isFileValid || !selectedMicro || !selectedDocType || !requestType) return;

    setLoading(true);
    try {
      const matrixAssignees = getAssigneesForSelection();
      const updatedDoc = await DocumentService.create(
          title, 
          description, 
          user,
          detectedState,
          detectedVersion,
          detectedProgress,
          file,
          {
              project: selectedProject,
              macro: selectedMacro,
              process: selectedProcess,
              micro: selectedMicro,
              docType: selectedDocType,
              assignees: matrixAssignees
          },
          existingDoc?.id // CRITICAL: Pass existing ID to consolidate history
      );

      navigate(`/doc/${updatedDoc.id}`);
    } catch (error: any) {
      console.error(error);
      alert('Error al gestionar documento: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const shouldShowOption = (type: RequestType): boolean => {
      if (!existingDoc || existingDoc.state === DocState.REJECTED) return true;
      const optionLevel = REQUEST_TYPE_LEVELS[type];
      return optionLevel >= existingDocLevel;
  };

  if (initializing) return <div className="p-8 text-center text-slate-500">Cargando permisos...</div>;

  const projects = getProjects();
  const macros = getMacros();
  const processes = getProcesses();
  const micros = getMicros();
  const docTypes = ['AS IS', 'FCE', 'PM', 'TO BE'];
  const allowedDocTypes = getAllowedDocTypes();

  return (
    <div className="max-w-4xl mx-auto pb-12">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 mb-6 text-sm">
            <ArrowLeft size={16} className="mr-1" />
            Volver
        </button>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-8 border-b border-slate-100 pb-4">
                <h1 className="text-2xl font-bold text-slate-900 mb-2">Nueva Solicitud</h1>
                <p className="text-slate-500">Carga de documento para gestión y aprobación.</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
                {/* Step 1: Hierarchy Selection */}
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                    <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <Layers size={18} className="text-indigo-600" />
                        1. Definición del Proceso
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proyecto</label>
                            <select value={selectedProject} onChange={(e) => handleProjectChange(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {projects.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Macroproceso</label>
                            <select value={selectedMacro} onChange={(e) => handleMacroChange(e.target.value)} disabled={!selectedProject} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {macros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proceso</label>
                            <select value={selectedProcess} onChange={(e) => handleProcessChange(e.target.value)} disabled={!selectedMacro} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {processes.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Microproceso</label>
                            <select value={selectedMicro} onChange={(e) => handleMicroChange(e.target.value)} disabled={!selectedProcess} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none font-medium text-indigo-900">
                                <option value="">-- Seleccionar --</option>
                                {micros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>

                        <div className="md:col-span-2 mt-2 border-t border-slate-200 pt-4">
                            <div className="flex justify-between items-center mb-1">
                                <label className="block text-xs font-semibold text-slate-500 uppercase">Tipo de Informe</label>
                                {selectedMicro && <span className="text-[10px] text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">Filtrado por Matriz</span>}
                            </div>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                {docTypes.map(type => {
                                    const isAllowed = allowedDocTypes.includes(type as DocType);
                                    return (
                                        <label key={type} className={`relative border rounded-lg p-3 text-center transition-all ${!selectedMicro ? 'bg-slate-100 border-slate-200 text-slate-400 cursor-not-allowed' : isAllowed ? (selectedDocType === type ? 'bg-indigo-600 text-white border-indigo-600 shadow-md transform scale-105 cursor-pointer' : 'bg-white border-slate-300 text-slate-600 hover:border-indigo-400 cursor-pointer') : 'bg-slate-50 border-slate-200 text-slate-300 cursor-not-allowed opacity-60'}`}>
                                            <input type="radio" name="docType" value={type} checked={selectedDocType === type} onChange={(e) => handleTypeChange(e.target.value)} className="hidden" disabled={!selectedMicro || !isAllowed} />
                                            <span className="text-sm font-medium flex items-center justify-center gap-1">{!isAllowed && selectedMicro && <Lock size={12} />}{type}</span>
                                        </label>
                                    );
                                })}
                            </div>
                        </div>

                        <div className={`md:col-span-2 mt-4 p-4 rounded-lg border transition-all ${existingDoc ? 'bg-amber-50 border-amber-100' : 'bg-indigo-50 border-indigo-100'}`}>
                             <div className="flex justify-between items-center mb-2">
                                 <label className={`block text-xs font-bold uppercase flex items-center gap-2 ${existingDoc ? 'text-amber-900' : 'text-indigo-900'}`}>
                                    {existingDoc ? <History size={16} /> : <ListFilter size={16} />}
                                    Etapa / Versión de Carga
                                 </label>
                                 {existingDoc && <span className="text-[10px] bg-white border border-amber-200 px-2 py-1 rounded text-amber-700 font-bold uppercase tracking-tighter shadow-sm animate-fadeIn">Documento Detectado</span>}
                             </div>

                             <select value={requestType} onChange={(e) => handleRequestTypeChange(e.target.value)} disabled={!selectedDocType} className="w-full p-3 border border-slate-200 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none font-medium text-slate-700 disabled:bg-slate-100">
                                <option value="">-- Seleccione qué etapa está subiendo --</option>
                                {shouldShowOption('INITIATED') && <option value="INITIATED">Iniciado (Versión 0.0)</option>}
                                {shouldShowOption('IN_PROCESS') && <option value="IN_PROCESS">En Proceso / Avance (Versión 0.n)</option>}
                                {shouldShowOption('INTERNAL') && <option value="INTERNAL">Revisión Interna (Versión v0.n)</option>}
                                {shouldShowOption('REFERENT') && <option value="REFERENT">Revisión Interna Referente (Versión v1.n.i)</option>}
                                {shouldShowOption('CONTROL') && <option value="CONTROL">Revisión Interna Control (Versión v1.n.iAR)</option>}
                            </select>

                            <div className="flex items-start gap-2 mt-2">
                                <Info size={14} className={existingDoc ? 'text-amber-600' : 'text-indigo-600'} />
                                <p className={`text-[10px] leading-tight ${existingDoc ? 'text-amber-700 font-medium' : 'text-indigo-600'}`}>
                                    {existingDoc 
                                        ? `Aviso: Se actualizará el registro existente. La última versión cargada fue la ${existingDoc.version} en estado ${STATE_CONFIG[existingDoc.state].label.split('(')[0]}. Las versiones anteriores han sido ocultadas.`
                                        : "* El archivo que subas debe coincidir estrictamente con la etapa seleccionada."
                                    }
                                </p>
                            </div>
                        </div>
                    </div>
                </div>

                {/* Step 2: File Upload */}
                {selectedMicro && selectedDocType && requestType && (
                    <div className="animate-fadeIn">
                         <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                            <Upload size={18} className="text-indigo-600" />
                            2. Carga de Archivo
                        </h2>

                        <div className={`mb-4 p-3 rounded border flex items-start gap-2 ${existingDoc ? 'bg-amber-50 border-amber-100 text-amber-900' : 'bg-blue-50 border-blue-100 text-blue-800'}`}>
                            <Info size={18} className="mt-0.5 flex-shrink-0" />
                            <div className="text-sm">
                                <p className="font-semibold">Nomenclatura Requerida:</p>
                                <p className="font-mono mt-1 text-xs md:text-sm font-bold">
                                    {selectedProject} - {selectedMicro} - {selectedDocType.replace(' ', '')} - [Versión]
                                </p>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-xl p-8 transition-colors flex flex-col items-center justify-center text-center group relative
                            ${isFileValid ? 'border-green-300 bg-green-50' : fileError.length > 0 ? 'border-red-300 bg-red-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                            {file ? (
                                isFileValid ? (
                                    <div className="text-green-700">
                                        <FileCheck size={48} className="mx-auto mb-3" />
                                        <p className="font-semibold text-lg">{file.name}</p>
                                        <p className="text-sm mt-1">Archivo válido y listo para consolidar</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600">
                                        <FileX size={48} className="mx-auto mb-3" />
                                        <p className="font-semibold text-lg">{file.name}</p>
                                        <div className="mt-3 text-sm text-left bg-white/50 p-3 rounded border border-red-200 inline-block">
                                            <ul className="list-disc pl-4 space-y-1">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-500 group-hover:text-indigo-600">
                                    <Upload size={40} className="mx-auto mb-3" />
                                    <p className="font-medium">Click para seleccionar archivo</p>
                                    <p className="text-xs mt-2 text-slate-400">Se validará la versión contra la etapa seleccionada.</p>
                                </div>
                            )}
                        </div>
                    </div>
                )}

                {/* Step 3: Confirmation Form */}
                {isFileValid && selectedMicro && selectedDocType && requestType && (
                    <div className="animate-fadeIn border-t border-slate-100 pt-6">
                         <div className={`flex items-center gap-3 p-4 rounded-lg border mb-6 ${existingDoc ? 'bg-amber-50 border-amber-200' : 'bg-slate-50 border-slate-200'}`}>
                            <FileType size={20} className="text-slate-500 flex-shrink-0" />
                            <div className="text-sm text-slate-700 grid grid-cols-2 md:grid-cols-4 gap-4 w-full">
                                <div><span className="text-slate-400 text-xs uppercase block">Nuevo Estado</span>{mapParserStateToEnum(parseDocumentFilename(file!.name).estado || '').replace(/_/g, ' ')}</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Nueva Versión</span>{detectedVersion}</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Progreso</span>{detectedProgress}%</div>
                                <div><span className="text-slate-400 text-xs uppercase block">Modo Carga</span>{existingDoc ? 'ACTUALIZAR HISTORIAL' : 'NUEVO REGISTRO'}</div>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Título del Documento</label>
                                <input type="text" value={title} readOnly className="w-full px-4 py-2 border border-slate-300 rounded-lg bg-slate-100 text-slate-600 focus:outline-none cursor-not-allowed" />
                            </div>
                             <div>
                                <label className="block text-sm font-medium text-slate-700 mb-1">Observación de esta Carga</label>
                                <input type="text" value={description} onChange={(e) => setDescription(e.target.value)} className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" required placeholder="Ej: Ajustes menores según reunión..." />
                            </div>
                        </div>

                        <div className="flex justify-end">
                            <button type="submit" disabled={loading} className={`flex items-center px-6 py-3 rounded-lg disabled:opacity-50 transition-colors shadow-md font-medium text-white ${existingDoc ? 'bg-amber-600 hover:bg-amber-700' : 'bg-green-600 hover:bg-green-700'}`}>
                                {loading ? 'Procesando...' : (
                                    <>
                                        {existingDoc ? <History size={18} className="mr-2" /> : <FilePlus size={18} className="mr-2" />}
                                        {existingDoc ? 'Actualizar y Consolidar Historial' : 'Cargar Nuevo Documento'}
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                )}
            </form>
        </div>
    </div>
  );
};

export default CreateDocument;

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HierarchyService, normalizeHeader } from '../services/firebaseBackend';
import { User, DocState, DocType, UserHierarchy, UserRole, Document, FullHierarchy } from '../types';
// Fix: Added missing import for STATE_CONFIG
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename } from '../utils/filenameParser';
import { Save, ArrowLeft, Upload, FileCheck, FileX, AlertTriangle, Info, Layers, FileType, FilePlus, ListFilter, Lock, RefreshCw, History } from 'lucide-react';

interface Props {
  user: User;
}

// Request Types mapped to Parser Logic
type RequestType = 'INITIATED' | 'IN_PROCESS' | 'INTERNAL' | 'REFERENT' | 'CONTROL';

// Map States to Levels for filtering
const STATE_LEVELS: Record<DocState, number> = {
    [DocState.NOT_STARTED]: 0,
    [DocState.INITIATED]: 1,
    [DocState.IN_PROCESS]: 2,
    [DocState.INTERNAL_REVIEW]: 3,
    [DocState.SENT_TO_REFERENT]: 4,
    [DocState.REFERENT_REVIEW]: 4,
    [DocState.SENT_TO_CONTROL]: 5,
    [DocState.CONTROL_REVIEW]: 5,
    [DocState.APPROVED]: 6,
    [DocState.REJECTED]: 0 // Special case
};

const REQUEST_TYPE_LEVELS: Record<RequestType, number> = {
    'INITIATED': 1,
    'IN_PROCESS': 2,
    'INTERNAL': 3,
    'REFERENT': 4,
    'CONTROL': 5
};

const CreateDocument: React.FC<Props> = ({ user }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Hook to access passed state
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(true);

  // Hierarchy Selection State with Strict Typing
  const [userHierarchy, setUserHierarchy] = useState<UserHierarchy>({});
  const [fullHierarchyCache, setFullHierarchyCache] = useState<FullHierarchy>({}); // Cache full hierarchy for assignments

  // Matrix Requirement Map (Project|Micro -> AllowedTypes[])
  const [requirementsMap, setRequirementsMap] = useState<Record<string, DocType[]>>({});

  const [selectedProject, setSelectedProject] = useState<string>('');
  const [selectedMacro, setSelectedMacro] = useState<string>('');
  const [selectedProcess, setSelectedProcess] = useState<string>('');
  const [selectedMicro, setSelectedMicro] = useState<string>('');
  const [selectedDocType, setSelectedDocType] = useState<DocType | ''>('');

  // New: Request Type for Safety
  const [requestType, setRequestType] = useState<RequestType | ''>('');

  // Existing Document State (for filtering)
  const [existingDoc, setExistingDoc] = useState<Document | null>(null);
  const [existingDocLevel, setExistingDocLevel] = useState<number>(0);

  // File Upload State
  const [file, setFile] = useState<File | undefined>(undefined);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');

  // Inferred Workflow State
  const [detectedState, setDetectedState] = useState<DocState>(DocState.INITIATED);
  const [detectedVersion, setDetectedVersion] = useState('0.0');
  const [detectedProgress, setDetectedProgress] = useState(10);

  // Cache of all docs for quick lookup
  const [allDocsCache, setAllDocsCache] = useState<Document[]>([]);

  useEffect(() => {
      loadData();
  }, []);

  // Effect to find existing document when selection changes
  useEffect(() => {
      if (selectedProject && selectedMicro && selectedDocType) {
          const found = allDocsCache.find(d => 
              normalizeHeader(d.project || '') === normalizeHeader(selectedProject) && 
              normalizeHeader(d.microprocess || d.title.split(' - ')[0] || '') === normalizeHeader(selectedMicro) &&
              d.docType === selectedDocType
          );

          if (found) {
              setExistingDoc(found);
              const level = STATE_LEVELS[found.state] || 0;
              setExistingDocLevel(level);
          } else {
              setExistingDoc(null);
              setExistingDocLevel(0);
          }
      } else {
          setExistingDoc(null);
          setExistingDocLevel(0);
      }

      setRequestType('');
      resetFile();

  }, [selectedProject, selectedMicro, selectedDocType, allDocsCache]);

  const loadData = async () => {
      try {
          const [reqMap, full, docs] = await Promise.all([
              HierarchyService.getRequiredTypesMap(),
              HierarchyService.getFullHierarchy(),
              DocumentService.getAll()
          ]);

          setRequirementsMap(reqMap);
          setAllDocsCache(docs);
          setFullHierarchyCache(full);

          if (user.role === UserRole.ADMIN) {
               const adminTree: UserHierarchy = {};
               Object.keys(full).forEach(p => {
                   adminTree[p] = {};
                   Object.keys(full[p]).forEach(m => {
                       adminTree[p][m] = {};
                       Object.keys(full[p][m]).forEach(proc => {
                           adminTree[p][m][proc] = full[p][m][proc].map(n => n.name);
                       });
                   });
               });
               setUserHierarchy(adminTree);
          } else {
              const userH = await HierarchyService.getUserHierarchy(user.id);
              setUserHierarchy(userH);
          }

          if (location.state?.prefill) {
              const { project, macro, process, micro, docType } = location.state.prefill;
              if (project) setSelectedProject(project);
              if (macro) setSelectedMacro(macro);
              if (process) setSelectedProcess(process);
              if (micro) setSelectedMicro(micro);

              if (docType && project && micro) {
                  const key = `${normalizeHeader(project)}|${normalizeHeader(micro)}`;
                  const allowed = reqMap[key] || [];
                  if (allowed.includes(docType)) {
                      setSelectedDocType(docType);
                  }
              }
          }
      } catch (e) {
          console.error("Error loading create document data", e);
      } finally {
          setInitializing(false);
      }
  };

  const getProjects = (): string[] => Object.keys(userHierarchy);
  const getMacros = (): string[] => (!selectedProject || !userHierarchy[selectedProject]) ? [] : Object.keys(userHierarchy[selectedProject]);
  const getProcesses = (): string[] => (!selectedProject || !selectedMacro || !userHierarchy[selectedProject]?.[selectedMacro]) ? [] : Object.keys(userHierarchy[selectedProject][selectedMacro]);
  const getMicros = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess) return [];
      const processes = userHierarchy[selectedProject]?.[selectedMacro];
      if (!processes) return [];
      return processes[selectedProcess] || [];
  };

  const getAllowedDocTypes = (): DocType[] => {
      if (!selectedProject || !selectedMicro) return [];
      const key = `${normalizeHeader(selectedProject)}|${normalizeHeader(selectedMicro)}`;
      return requirementsMap[key] || [];
  };

  const getAssigneesForSelection = (): string[] => {
      if (!selectedProject || !selectedMacro || !selectedProcess || !selectedMicro) return [];
      const nodes = fullHierarchyCache[selectedProject]?.[selectedMacro]?.[selectedProcess] || [];
      const node = nodes.find(n => n.name === selectedMicro);
      return node?.assignees || [];
  };

  const handleProjectChange = (val: string) => {
      setSelectedProject(val); setSelectedMacro(''); setSelectedProcess(''); setSelectedMicro(''); resetFile();
  };

  const handleMacroChange = (val: string) => {
      setSelectedMacro(val); setSelectedProcess(''); setSelectedMicro(''); resetFile();
  };

  const handleProcessChange = (val: string) => {
      setSelectedProcess(val); setSelectedMicro(''); resetFile();
  };

  const handleMicroChange = (val: string) => {
      setSelectedMicro(val); setSelectedDocType(''); resetFile();
  }

  const handleTypeChange = (val: string) => {
      setSelectedDocType(val as DocType); resetFile();
  }

  const handleRequestTypeChange = (val: string) => {
      setRequestType(val as RequestType); resetFile();
  }

  const resetFile = () => {
      setFile(undefined); setFileError([]); setIsFileValid(false); setTitle(''); setDescription('');
      if (fileInputRef.current) { fileInputRef.current.value = ''; }
  };

  const mapParserStateToEnum = (parserState: string): DocState => {
      switch (parserState) {
          case 'Iniciado': return DocState.INITIATED;
          case 'En Proceso': return DocState.IN_PROCESS;
          case 'En revisión interna': return DocState.INTERNAL_REVIEW;
          case 'Enviado a Referente': return DocState.SENT_TO_REFERENT;
          case 'Revisión Interna Referente': return DocState.REFERENT_REVIEW;
          case 'Enviado a Control de Gestión': return DocState.SENT_TO_CONTROL;
          case 'Revisión Interna Control': return DocState.CONTROL_REVIEW;
          case 'Aprobado': return DocState.APPROVED;
          default: return DocState.INITIATED;
      }
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0]) {
          const selectedFile = e.target.files[0];
          setFile(selectedFile);

          const result = parseDocumentFilename(
              selectedFile.name,
              selectedProject,
              selectedMicro,
              selectedDocType || undefined,
              requestType || undefined
          );

          if (result.valido) {
              setIsFileValid(true);
              setFileError([]);
              const cleanMicro = result.microproceso || selectedMicro;
              const cleanType = result.tipo || selectedDocType;
              setTitle(`${cleanMicro} - ${cleanType}`);
              setDescription(`Carga de documento: ${cleanType} (${result.nomenclatura})`);
              if (result.estado) setDetectedState(mapParserStateToEnum(result.estado));
              if (result.nomenclatura) setDetectedVersion(result.nomenclatura);
              if (result.porcentaje) setDetectedProgress(result.porcentaje);
          } else {
              setIsFileValid(false);
              setFileError(result.errores);
              setTitle('');
              setDescription('');
          }
      }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title || !description || !file || !isFileValid || !selectedMicro || !selectedDocType || !requestType) return;

    setLoading(true);
    try {
      const matrixAssignees = getAssigneesForSelection();
      const updatedDoc = await DocumentService.create(
          title, 
          description, 
          user,
          detectedState,
          detectedVersion,
          detectedProgress,
          file,
          {
              project: selectedProject,
              macro: selectedMacro,
              process: selectedProcess,
              micro: selectedMicro,
              docType: selectedDocType,
              assignees: matrixAssignees
          },
          existingDoc?.id // CRITICAL: Pass existing ID to consolidate history
      );

      navigate(`/doc/${updatedDoc.id}`);
    } catch (error: any) {
      console.error(error);
      alert('Error al gestionar documento: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const shouldShowOption = (type: RequestType): boolean => {
      if (!existingDoc || existingDoc.state === DocState.REJECTED) return true;
      const optionLevel = REQUEST_TYPE_LEVELS[type];
      return optionLevel >= existingDocLevel;
  };

  if (initializing) return <div className="p-8 text-center text-slate-500">Cargando permisos...</div>;

  const projects = getProjects();
  const macros = getMacros();
  const processes = getProcesses();
  const micros = getMicros();
  const docTypes = ['AS IS', 'FCE', 'PM', 'TO BE'];
  const allowedDocTypes = getAllowedDocTypes();

  return (
    <div className="max-w-4xl mx-auto pb-12">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 mb-6 text-sm">
            <ArrowLeft size={16} className="mr-1" />
            Volver
        </button>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
            <div className="mb-8 border-b border-slate-100 pb-4">
                <h1 className="text-2xl font-bold text-slate-900 mb-2">Nueva Solicitud</h1>
                <p className="text-slate-500">Carga de documento para gestión y aprobación.</p>
            </div>

            <form onSubmit={handleSubmit} className="space-y-8">
                {/* Step 1: Hierarchy Selection */}
                <div className="bg-slate-50 p-6 rounded-xl border border-slate-200">
                    <h2 className="text-sm font-bold text-slate-800 uppercase tracking-wide mb-4 flex items-center gap-2">
                        <Layers size={18} className="text-indigo-600" />
                        1. Definición del Proceso
                    </h2>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proyecto</label>
                            <select value={selectedProject} onChange={(e) => handleProjectChange(e.target.value)} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {projects.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Macroproceso</label>
                            <select value={selectedMacro} onChange={(e) => handleMacroChange(e.target.value)} disabled={!selectedProject} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {macros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Proceso</label>
                            <select value={selectedProcess} onChange={(e) => handleProcessChange(e.target.value)} disabled={!selectedMacro} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none">
                                <option value="">-- Seleccionar --</option>
                                {processes.map((p) => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div>
                            <label className="block text-xs font-semibold text-slate-500 mb-1 uppercase">Microproceso</label>
                            <select value={selectedMicro} onChange={(e) => handleMicroChange(e.target.value)} disabled={!selectedProcess} className="w-full p-2.5 border border-slate-300 rounded-lg bg-white disabled:bg-slate-100 disabled:text-slate-400 focus:ring-2 focus:ring-indigo-500 outline-none font-medium text-indigo-900">
                                <option value="">-- Seleccionar --</option>
                                {micros.map((m) => <option key={m} value={m}>{m}</option>)}
                            </select>
                        </div>

                        <div className="md:col-span-2 mt-2 border-t border-slate-200 pt-4">
                            <div className="flex justify-between items-center mb-1">
                                <label className="block text-xs font-semibold text-slate-500 uppercase">Tipo de Informe</label>
                                {selectedMicro && <span className="text-[10px] text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded border border-indigo-100">Filtrado por Matriz</span>}
                            </div>
                            <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                {docTypes.map(type => {
                                    const isAllowed = allowedDocTypes.includes(type as DocType);
                                    return (
                                        <label key={type} className={`relative border rounded-lg p-3 text-center transition-all ${!selectedMicro ? 'bg-slate-100 border-slate-200 text-slate-400 cursor-not-allowed' : isAllowed ? (selectedDocType === type ? 'bg-indigo-600 text-white border-indigo-600 shadow-md transform scale-105 cursor-pointer' : 'bg-white border-slate-300 text-slate-600 hover:border-indigo-400 cursor-pointer') : 'bg-slate-50 border-slate-200 text-slate-300 cursor-not-allowed opacity-60'}`}>
                                            <input type="radio" name="docType" value={type} checked={selectedDocType === type} onChange={(e) => handleTypeChange(e.target.value)} className="hidden" disabled={!selectedMicro || !isAllowed} />
                                            <span className="text-sm font-medium flex items-center justify-center gap-1">{!isAllowed && selectedMicro && <Lock size={12} />}{type}</span>
                                        </label>
                                    );
                                })}
                            </div>
                        </div>

                        <div className={`md:col-span-2 mt-4 p-4 rounded-lg border transition-all ${existingDoc ? 'bg-amber-50 border-amber-100' : 'bg-indigo-50 border-indigo-100'}`}>
                             <div className="flex justify-between items-center mb-2">
                                 <label className={`block text-xs font-bold uppercase flex items-center gap-2 ${existingDoc ? 'text-amber-900' : 'text-indigo-900'}`}>
                                    {existingDoc ? <History size={16} /> : <ListFilter size={16} />}
                                    Etapa / Versión de Carga
                                 </label>
                                 {existingDoc && <span className="text-[10px] bg-white border border-amber-200 px-2 py-1 rounded text-amber-700 font-bold uppercase tracking-tighter shadow-sm animate-fadeIn">Documento Detectado</span>}
                             </div>

                             <select value={requestType} onChange={(e) => handleRequestTypeChange(e.target.value)} disabled={!selectedDocType} className="w-full p-3 border border-slate-200 rounded-lg bg-white focus:ring-2 focus:ring-indigo-500 outline-none font-medium text-slate-700 disabled:bg-slate-100">
                                <option value="">-- Seleccione qué etapa está subiendo --</option>
                                {shouldShowOption('INITIATED') && <option value="INITIATED">Iniciado (Versión 0.0)</option>}
                                {shouldShowOption('IN_PROCESS') && <option value="IN_PROCESS">En Proceso / Avance (Versión 0.n)</option>}
                                {shouldShowOption('INTERNAL') && <option value="INTERNAL">Revisión Interna (Versión v0.n)</option>}
                                {shouldShowOption('REFERENT') && <option value="REFERENT">Revisión Interna Referente (Versión v1.n.i)</option>}
                                {shouldShowOption('CONTROL') && <option value="CONTROL">Revisión Interna Control (Versión v1.n.iAR)</option>}
                            </select>

                            <div className="flex items-start gap-2 mt-2">
                                <Info size={14} className={existingDoc ? 'text-amber-600' : 'text-indigo-600'} />
                                <p className={`text-[10px] leading-tight ${existingDoc ? 'text-amber-700 font-medium' : 'text-indigo-600'}`}>
                                    {existingDoc 
