export const HistoryService = {
  getHistory: async (docIds: string | string[]): Promise<DocHistory[]> => {
    const ids = Array.isArray(docIds) ? docIds : [docIds];
    if (ids.length === 0) return [];

    // Firestore limit is 10 for 'in' queries, but we usually have few fragments
    const q = query(collection(db, "history"), where("documentId", "in", ids.slice(0, 10)));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  },
  getAll: async (): Promise<DocHistory[]> => {
    const q = query(collection(db, "history"), orderBy("timestamp", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => doc.data() as DocHistory);
  },
  log: async (docId: string, user: User, action: string, prev: DocState, next: DocState, comment: string, version?: string) => {
    const entryId = `hist-${docId}-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`;
    const newEntry: DocHistory = { 
        id: entryId, 
        documentId: docId, 
        userId: user.id, 
        userName: user.name, 
        action, 
        previousState: prev, 
        newState: next, 
        version: version || '-',
        comment, 
        timestamp: new Date().toISOString() 
    };
    await addDoc(collection(db, "history"), newEntry);
  }
};

export const DocumentService = {
  getAll: async (): Promise<Document[]> => {
    const q = query(collection(db, "documents"), orderBy("updatedAt", "desc"));
    const querySnapshot = await getDocs(q);
    return querySnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Document));
  },
  getById: async (id: string): Promise<Document | null> => {
    const docRef = doc(db, "documents", id);
    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? ({ id: docSnap.id, ...docSnap.data() } as Document) : null;
  },
  getRelatedDocIds: async (project: string, micro: string, type: string): Promise<string[]> => {
      const q = query(
          collection(db, "documents"), 
          where("project", "==", project),
          where("docType", "==", type)
      );
      const snap = await getDocs(q);
      const normalizedMicro = normalizeHeader(micro);
      return snap.docs
          .filter(d => normalizeHeader(d.data().microprocess || d.data().title.split(' - ')[0]) === normalizedMicro)
          .map(d => d.id);
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any, existingId?: string): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = state === DocState.INTERNAL_REVIEW || state === DocState.SENT_TO_REFERENT || state === DocState.SENT_TO_CONTROL;
    const version = initialVersion || '0.0';
    const info = determineStateFromVersion(version);
    const progress = initialProgress !== undefined ? initialProgress : info.progress;

    if (existingId) {
        const docRef = doc(db, "documents", existingId);
        const oldSnap = await getDoc(docRef);
        const oldData = oldSnap.data() as Document;
        const updateData: Partial<Document> = { state, version, progress, description, hasPendingRequest: isSubmission, updatedAt: new Date().toISOString() };
        await updateDoc(docRef, updateData);
        await HistoryService.log(existingId, author, 'Nueva Versión (Carga)', oldData.state, state, `Carga de archivo versión ${version}`, version);
        return { id: existingId, ...oldData, ...updateData } as Document;
    } else {
        const mergedAssignees = Array.from(new Set([...(hierarchy?.assignees || []), author.id]));
        const newDocData: Omit<Document, 'id'> = {
          title, description, authorId: author.id, authorName: author.name, assignedTo: author.id, assignees: mergedAssignees, state, version, progress, hasPendingRequest: isSubmission, files: [], createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
        };
        const docRef = await addDoc(collection(db, "documents"), newDocData);
        await HistoryService.log(docRef.id, author, 'Creación', DocState.NOT_STARTED, state, `Iniciado Versión ${version}`, version);
        return { id: docRef.id, ...newDocData } as Document;
    }
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "documents", id)); },
  transitionState: async (docId: string, user: User, action: any, comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Documento no encontrado");
      const currentDoc = docSnap.data() as Document;
      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;
      const actionLabels: Record<string, string> = { 'APPROVE': 'Aprobación', 'REJECT': 'Rechazo', 'COMMENT': 'Observación', 'REQUEST_APPROVAL': 'Solicitud de Revisión', 'ADVANCE': 'Avance de Flujo' };
      const displayAction = actionLabels[action] || action;
      if (customVersion) {
        newVersion = customVersion;
        const info = determineStateFromVersion(customVersion);
        newState = info.state;
      }
      if (action === 'APPROVE') hasPending = false;
      else if (action === 'REJECT') { hasPending = false; newState = determineStateFromVersion(newVersion).state; }
      else if (action === 'REQUEST_APPROVAL') hasPending = true;
      const { progress: newProgress } = determineStateFromVersion(newVersion);
      await updateDoc(docRef, { state: newState, version: newVersion, progress: newProgress, hasPendingRequest: hasPending, updatedAt: new Date().toISOString() });
      await HistoryService.log(docId, user, displayAction, currentDoc.state, newState, comment, newVersion);
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const node: ProcessNode = { name: data.name, docId: doc.id, assignees: data.assignees || [], referentIds: data.referentIds || [], requiredTypes: data.requiredTypes || [], active: data.active !== false };
      if (!hierarchy[data.project]) hierarchy[data.project] = {};
      if (!hierarchy[data.project][data.macroprocess || 'Sin Macro']) hierarchy[data.project][data.macroprocess || 'Sin Macro'] = {};
      if (!hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process]) hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process] = [];
      hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process].push(node);
    });
    return hierarchy;
  },
  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};
      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (!hierarchy[data.project]) hierarchy[data.project] = {};
          if (!hierarchy[data.project][data.macroprocess || 'Sin Macro']) hierarchy[data.project][data.macroprocess || 'Sin Macro'] = {};
          if (!hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process]) hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process] = [];
          hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process].push(data.name);
      });
      return hierarchy;
  },
  updateMatrixAssignment: async (docId: string, assignees: string[]) => { await updateDoc(doc(db, "process_matrix", docId), { assignees }); },
  updateReferentLinks: async (referentId: string, selectedDocIds: string[]) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          let referents = d.data().referentIds || [];
          const isSelected = selectedDocIds.includes(d.id);
          if (isSelected && !referents.includes(referentId)) batch.update(d.ref, { referentIds: [...referents, referentId] });
          else if (!isSelected && referents.includes(referentId)) batch.update(d.ref, { referentIds: referents.filter((id:string) => id !== referentId) });
      });
      await batch.commit();
  },
  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const current = new Set(snap.data().requiredTypes || []);
          if (current.has(type)) current.delete(type); else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },
  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      await setDoc(doc(db, "process_matrix", id), { project, macroprocess: macro, process, name, assignees, referentIds: [], requiredTypes, active: true });
  },
  deleteMicroprocess: async (docId: string) => { await deleteDoc(doc(db, "process_matrix", docId)); },
  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(d => {
          const key = `${normalizeHeader(d.data().project)}|${normalizeHeader(d.data().name)}`;
          map[key] = d.data().requiredTypes || [];
      });
      return map;
  },
  toggleProcessStatus: async (docId: string, currentStatus: boolean) => { await updateDoc(doc(db, "process_matrix", docId), { active: !currentStatus }); },
  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') q = query(collection(db, "process_matrix"), where("project", "==", name));
      else if (level === 'MACRO') q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      else q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },
  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', oldName: string, newName: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') q = query(collection(db, "process_matrix"), where("project", "==", oldName));
      else if (level === 'MACRO') q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
      else q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          const update: any = {};
          if (level === 'PROJECT') update.project = newName;
          else if (level === 'MACRO') update.macroprocess = newName;
          else update.process = newName;
          batch.update(d.ref, update);
      });
      await batch.commit();
  },
  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      await updateDoc(doc(db, "process_matrix", docId), { project: targetProject, macroprocess: targetMacro, process: targetProcess });
  },
  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS'); if (fce) requiredTypes.push('FCE'); if (pm) requiredTypes.push('PM'); if (tobe) requiredTypes.push('TO BE');
           batch.set(doc(db, "process_matrix", generateMatrixId(project, micro)), { project, macroprocess: 'Macroproceso General', process: 'Proceso General', name: micro, assignees: [], referentIds: [], requiredTypes, active: true });
      }
      await batch.commit();
  }
};

export const DatabaseService = {
    exportData: async (): Promise<string> => {
        const collections = ['users', 'documents', 'history', 'process_matrix', 'notifications', 'referents'];
        const data: any = {};
        for (const colName of collections) {
            const snapshot = await getDocs(collection(db, colName));
            data[colName] = snapshot.docs.map(d => ({ _id: d.id, ...d.data() }));
        }
        return JSON.stringify(data, null, 2);
    },
    importData: async (jsonString: string) => {
        const data = JSON.parse(jsonString);
        for (const colName of Object.keys(data)) {
            await deleteCollectionInBatches(colName);
            const items = data[colName];
            let batch = writeBatch(db);
            let count = 0;
            for (const item of items) {
                const { _id, ...docData } = item;
                batch.set(doc(db, colName, _id), docData);
                count++;
                if (count >= 400) { await batch.commit(); batch = writeBatch(db); count = 0; }
            }
            if (count > 0) await batch.commit();
        }
    },
    fullSystemResetAndImport: async (rulesCSV: string, historyCSV: string, onProgress: (percent: number, status: string) => void): Promise<{ created: number, historyMatched: number }> => {
        onProgress(5, "Limpiando...");
        await deleteCollectionInBatches("documents"); await deleteCollectionInBatches("history"); await deleteCollectionInBatches("process_matrix"); await deleteCollectionInBatches("notifications");
        onProgress(10, "Reglas...");
        const rows = rulesCSV.split(/\r?\n/).filter(r => r.trim().length > 0);
        const headers = rows[0].split(/[;,]/).map(h => normalizeHeader(h));
        const idxProject = headers.findIndex(h => h.includes('PROYECTO'));
        const idxMacro = headers.findIndex(h => h.includes('MACRO'));
        const idxProcess = headers.findIndex(h => h === 'PROCESO');
        const idxMicro = headers.findIndex(h => h.includes('MICRO'));
        const idxAnalyst = headers.findIndex(h => h.includes('ANALISTA') || h.includes('RESPONSABLE'));
        const idxAsis = headers.findIndex(h => h.includes('ASIS') || h.includes('AS IS'));
        const idxFce = headers.findIndex(h => h.includes('FCE'));
        const idxPm = headers.findIndex(h => h.includes('PM'));
        const idxTobe = headers.findIndex(h => h.includes('TOBE') || h.includes('TO BE'));
        const allUsers = await UserService.getAll();
        let createdCount = 0;
        let batch = writeBatch(db);
        let opCount = 0;
        for (let i = 1; i < rows.length; i++) {
            const cols = rows[i].split(/[;,]/).map(c => c.trim());
            if (cols.length < 3) continue;
            const project = cols[idxProject] || 'GENERAL';
            const assignees = findUserIdsFromCSV(allUsers, cols[idxAnalyst]);
            const requiredTypes: string[] = [];
            if (cols[idxAsis] === '1') requiredTypes.push('AS IS');
            if (cols[idxFce] === '1') requiredTypes.push('FCE');
            if (cols[idxPm] === '1') requiredTypes.push('PM');
            if (cols[idxTobe] === '1') requiredTypes.push('TO BE');
            batch.set(doc(db, "process_matrix", generateMatrixId(project, cols[idxMicro])), { project, macroprocess: cols[idxMacro] || 'General', process: cols[idxProcess] || 'General', name: cols[idxMicro], assignees, referentIds: [], requiredTypes, active: true });
            opCount++; createdCount++;
            if (opCount >= 400) { await batch.commit(); batch = writeBatch(db); opCount = 0; }
        }
        if (opCount > 0) await batch.commit();
        onProgress(100, "Finalizando...");
        return { created: createdCount, historyMatched: 0 };
    }
};

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, ArrowRight, History as HistoryIcon, Layers } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                     const emails = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.email).filter((e: string | undefined) => e) as string[];
                     setAssigneeEmails(emails);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          // UNIFIED HISTORY LOGIC: Search for all IDs related to this Project + Micro + Type
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds), // Fetch history for all fragments
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = findCoordinator(allUsers);
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const findCoordinator = (users: User[]) => users.find(u => ['COORDINATOR', 'COORDINADOR'].includes((u.role || '').toString().toUpperCase())) || users.find(u => ['ADMIN', 'ADMINISTRADOR'].includes((u.role || '').toString().toUpperCase()));

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const handleNewRequest = () => { if (!doc) return; navigate('/new', { state: { prefill: { project: doc.project, macro: doc.macroprocess, process: doc.process, micro: doc.microprocess, docType: doc.docType } } }); };
  const handleDeleteClick = () => { setShowDeleteModal(true); };
  const confirmDelete = async () => { if (!doc) return; try { setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); } catch (e: any) { alert('Error al eliminar: ' + e.message); setLoading(false); } };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Por favor escribe una observación antes de guardar.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Por favor agrega un comentario/observación antes de rechazar.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación de versión.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      if (window.confirm(`¿Confirma ${pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR'} la solicitud cargando el archivo ${detectedVersion}?`)) {
          setShowResponseModal(false); await executeTransition(pendingAction, comment, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;
  const handleAnalystNotificationToCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimada/o,\nPara vuestra aprobación, adjunto el Informe "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nPuede revisar los detalles en: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyExternal = () => {
      if (!doc) return;
      const subject = encodeURIComponent(`Solicitud de Aprobación ${doc.docType || ''} - ${doc.microprocess || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimado,\nPara vuestra aprobación, adjunto el Informe: ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&cc=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) return;
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimado ${assigneeNames[0] || 'Analista'},\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado: ${STATE_CONFIG[doc.state].label}\n\nVínculo: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center flex flex-col items-center justify-center"><div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400"><FileX size={32} /></div><h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2><button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg">Volver</button></div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;
  const canNotifyAuthor = isCoordinatorOrAdmin && doc.state !== DocState.NOT_STARTED; 
  const canNotifyExternal = (isCoordinatorOrAdmin) && (doc.state === DocState.SENT_TO_REFERENT || doc.state === DocState.SENT_TO_CONTROL || doc.state === DocState.REFERENT_REVIEW || doc.state === DocState.CONTROL_REVIEW);
  const canNotifyCoordinator = isAnalystAssigned && [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state);

  return (
    <div className="max-w-4xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm"><ArrowLeft size={16} className="mr-1" /> Volver</button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button type="button" onClick={handleDeleteClick} className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"><Trash2 size={16} className="mr-1" /> Eliminar</button>
        )}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start ${config.color}`}><Activity size={16} className="mr-2" />{config.label}</div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div><p className="text-slate-500">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-medium text-slate-800">{name}</p>) : <p className="font-medium text-slate-800">{doc.authorName}</p>}</div>
            <div><p className="text-slate-500">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-200 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full" style={{ width: `${config.progress}%` }}></div></div><span className="font-medium">{config.progress}%</span></div></div>
            <div><p className="text-slate-500">Actualizado</p><p className="text-slate-800">{new Date(doc.updatedAt).toLocaleDateString()}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="md:col-span-2 space-y-6">
            {!canEdit && <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 flex gap-3 text-sm text-yellow-700"><Lock size={20} className="text-yellow-400" /> Solo lectura.</div>}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-semibold text-slate-800 mb-4 flex items-center gap-2"><PlusCircle size={18} className="text-indigo-600"/> Acciones de Flujo</h3>
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button onClick={handleNewRequest} className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"><PlusCircle size={20} className="mr-2" />{doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Nueva Solicitud / Continuar Flujo'}</button>
                         </div>
                     )}
                     <textarea className="w-full p-3 border border-slate-300 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500" rows={3} placeholder="Observaciones..." value={comment} onChange={(e) => setComment(e.target.value)} />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-medium shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>
                        {canNotifyCoordinator && <button onClick={handleAnalystNotificationToCoordinator} className="flex items-center px-4 py-2 bg-blue-100 text-blue-700 hover:bg-blue-200 rounded-lg text-sm font-medium border border-blue-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar coordinador</button>}
                        {canNotifyAuthor && <button onClick={handleNotifyAnalyst} className="flex items-center px-4 py-2 bg-slate-100 text-slate-700 hover:bg-slate-200 rounded-lg text-sm font-medium border border-slate-200 shadow-sm"><Mail size={16} className="mr-2" /> Notificar Analista</button>}
                        {canNotifyExternal && <button onClick={handleNotifyExternal} className="flex items-center px-4 py-2 bg-purple-600 text-white rounded-lg hover:bg-purple-700 text-sm font-medium shadow-sm transition-colors"><ExternalLink size={16} className="mr-2" /> Notificar Referentes</button>}
                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-medium shadow-sm">Reiniciar Flujo</button>}
                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-medium shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-medium border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* HISTORIAL COMPLETO UNIFICADO */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[500px]">
            <div className="flex items-center justify-between mb-6 border-b border-slate-100 pb-3">
                <h3 className="font-semibold text-slate-800 flex items-center gap-2">
                    <HistoryIcon size={18} className="text-indigo-600" /> Historial Unificado
                </h3>
                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-indigo-50 border border-indigo-100 rounded-full text-[10px] text-indigo-700 font-bold uppercase" title="Muestra historial de todas las versiones del microproceso">
                   <Layers size={12} /> Línea de Tiempo de Proceso
                </div>
            </div>

            <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                      <Clock size={40} className="mb-2 opacity-20" />
                      <p className="text-xs italic">Sin historial registrado.</p>
                  </div>
                ) : (
                  <div className="space-y-8 pl-5 border-l-2 border-slate-100 relative ml-2">
                      {history.map((h) => {
                          const isApprove = h.action === 'Aprobación';
                          const isReject = h.action === 'Rechazo';
                          const isNewVer = h.action.includes('Nueva Versión');
                          return (
                              <div key={h.id} className="relative group animate-fadeIn">
                                  <div className={`absolute -left-[27px] top-1 h-3.5 w-3.5 rounded-full border-2 border-white shadow-sm transition-transform group-hover:scale-125
                                      ${h.action === 'Observación' ? 'bg-indigo-400' : 
                                        h.action === 'Creación' ? 'bg-green-500' : 
                                        isApprove ? 'bg-green-600' : 
                                        isReject ? 'bg-red-500' : 
                                        isNewVer ? 'bg-blue-500' : 'bg-slate-400'}`}>
                                  </div>
                                  <div className="flex items-center gap-1 text-[10px] font-bold text-slate-400 mb-1">
                                      <Clock size={10} /> {formatDate(h.timestamp)}
                                  </div>
                                  <div className="flex flex-wrap items-center gap-x-2 gap-y-1 mb-1.5">
                                      <span className={`text-sm font-bold ${isReject ? 'text-red-700' : isApprove ? 'text-green-700' : 'text-slate-800'}`}>{h.action}</span>
                                      <span className="text-xs text-slate-400 font-medium">por</span>
                                      <span className="text-xs font-bold text-slate-600 flex items-center gap-1"><UserIcon size={10} /> {h.userName}</span>
                                  </div>
                                  <div className="flex items-center gap-2 mb-2">
                                      <div className="text-[10px] bg-slate-800 text-white px-2 py-0.5 rounded font-mono font-bold tracking-tight">Versión: {h.version || '-'}</div>
                                      {h.previousState !== h.newState && (
                                          <div className="flex items-center gap-1 text-[9px] text-slate-400 uppercase font-bold">
                                              {STATE_CONFIG[h.previousState]?.label.split('(')[0].trim()} <ArrowRight size={10} /> <span className="text-indigo-600">{STATE_CONFIG[h.newState]?.label.split('(')[0].trim()}</span>
                                          </div>
                                      )}
                                  </div>
                                  {h.comment && <div className="relative p-3 bg-slate-50 rounded-lg border border-slate-100 text-xs text-slate-600 italic leading-relaxed shadow-sm"><div className="absolute top-0 left-0 w-1 h-full bg-slate-200 rounded-l-lg"></div>"{h.comment}"</div>}
                              </div>
                          );
                      })}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-4 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 leading-tight">Este microproceso se encuentra en estado <b>Pendiente</b> según la matriz. No existen documentos cargados aún.</p>
              </div>
            )}
        </div>
      </div>

      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-lg overflow-hidden">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-lg flex flex-col gap-2"><div className="flex items-start gap-3"><Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" /><div><p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p><p className="text-xs text-blue-900 leading-relaxed">{getCoordinatorRuleHint(doc.state, pendingAction)}</p></div></div></div>
                        <div className={`border-2 border-dashed rounded-lg p-6 transition-colors flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-300 bg-green-50' : fileError.length > 0 ? 'border-red-300 bg-red-50' : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50'}`}><input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />{responseFile ? (isFileValid ? <div className="text-green-700"><CheckCircle size={32} className="mx-auto mb-2" /><p className="font-semibold text-sm">{responseFile.name}</p><p className="text-xs mt-1">Versión Detectada: <strong>{detectedVersion}</strong></p></div> : <div className="text-red-600"><FileX size={32} className="mx-auto mb-2" /><p className="font-semibold text-sm">{responseFile.name}</p><div className="mt-2 text-xs text-left bg-white/50 p-2 rounded border border-red-200"><ul className="list-disc pl-4 space-y-1">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul></div></div>) : <div className="text-slate-500 group-hover:text-indigo-600"><Upload size={32} className="mx-auto mb-2" /><p className="font-medium text-sm">Click para cargar respuesta</p><p className="text-xs mt-1 text-slate-400">Debe cumplir con la nomenclatura de la etapa.</p></div>}</div>
                        <div className="flex justify-end gap-3 pt-4"><button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-700 text-sm">Cancelar</button><button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-4 py-2 rounded-lg text-white text-sm font-bold shadow-sm transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:cursor-not-allowed`}><Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}</button></div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-xl shadow-xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between"><h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3><button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button></div>
                  <div className="p-6"><p className="text-slate-700 mb-4">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>?</p><div className="flex justify-end gap-3"><button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600">Cancelar</button><button onClick={confirmDelete} className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">Sí, Eliminar</button></div></div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, ArrowRight, History as HistoryIcon, Layers } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Response Modal State
  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);

  // File Upload inside Modal
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                     const emails = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.email).filter((e: string | undefined) => e) as string[];
                     setAssigneeEmails(emails);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          // LÓGICA DE UNIFICACIÓN: Buscar IDs hermanos para mostrar todo el historial del proceso
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const handleNewRequest = () => { if (!doc) return; navigate('/new', { state: { prefill: { project: doc.project, macro: doc.macroprocess, process: doc.process, micro: doc.microprocess, docType: doc.docType } } }); };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Por favor escribe una observación antes de guardar.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Por favor agrega un comentario/observación antes de rechazar.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación de versión.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      if (window.confirm(`¿Confirma ${pendingAction === 'APPROVE' ? 'APROBAR' : 'RECHAZAR'} la solicitud cargando el archivo ${detectedVersion}?`)) {
          setShowResponseModal(false); await executeTransition(pendingAction, comment, responseFile, detectedVersion);
      }
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center flex flex-col items-center justify-center"><div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4 text-slate-400"><FileX size={32} /></div><h2 className="text-xl font-bold text-slate-700 mb-2">Documento no encontrado</h2><button onClick={() => navigate('/')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg">Volver</button></div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const canRestart = isAnalystAssigned && doc.state === DocState.REJECTED;
  const isDocActive = doc.state !== DocState.APPROVED;
  const canApprove = isCoordinatorOrAdmin && isDocActive;
  const canReject = isCoordinatorOrAdmin && isDocActive;

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium"><ArrowLeft size={16} className="mr-1" /> Volver</button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button type="button" onClick={() => setShowDeleteModal(true)} className="flex items-center text-red-500 hover:text-red-700 text-sm font-medium px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg transition-colors"><Trash2 size={16} className="mr-1" /> Eliminar</button>
        )}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-1">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-bold text-slate-900">{doc.title}</h1>
                <p className="text-slate-500 mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-1.5 rounded-lg text-sm font-semibold flex items-center self-start shadow-sm border ${config.color}`}><Activity size={16} className="mr-2" />{config.label}</div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
            <div><p className="text-slate-500 text-[11px] uppercase font-bold tracking-wider mb-1">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-800">{name}</p>) : <p className="font-bold text-slate-800">{doc.authorName}</p>}</div>
            <div><p className="text-slate-500 text-[11px] uppercase font-bold tracking-wider mb-1">Versión Actual</p><p className="font-mono text-slate-800 font-bold">{doc.version}</p></div>
            <div><p className="text-slate-500 text-[11px] uppercase font-bold tracking-wider mb-1">Progreso</p><div className="flex items-center gap-2"><div className="flex-1 bg-slate-100 rounded-full h-2 w-20"><div className="bg-indigo-600 h-2 rounded-full shadow-[0_0_8px_rgba(79,70,229,0.4)]" style={{ width: `${config.progress}%` }}></div></div><span className="font-bold text-slate-700">{config.progress}%</span></div></div>
            <div><p className="text-slate-500 text-[11px] uppercase font-bold tracking-wider mb-1">Actualizado</p><p className="font-bold text-slate-800">{new Date(doc.updatedAt).toLocaleDateString('es-CL')}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        <div className="lg:col-span-2 space-y-6">
            {!canEdit && <div className="bg-yellow-50 border-l-4 border-yellow-400 p-4 flex gap-3 text-sm text-yellow-700"><Lock size={20} className="text-yellow-400" /> Modo solo lectura.</div>}
            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2 uppercase text-xs tracking-widest"><PlusCircle size={18} className="text-indigo-600"/> Acciones de Flujo</h3>
                     {user.role === UserRole.ANALYST && doc.state !== DocState.APPROVED && (
                         <div className="mb-6 pb-6 border-b border-slate-100">
                             <button onClick={handleNewRequest} className="w-full flex items-center justify-center px-4 py-3 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 font-bold shadow-md transition-all active:scale-95"><PlusCircle size={20} className="mr-2" />{doc.state === DocState.NOT_STARTED ? 'Iniciar Solicitud' : 'Cargar Nueva Versión'}</button>
                         </div>
                     )}
                     <textarea className="w-full p-3 border border-slate-200 rounded-lg text-sm mb-4 outline-none focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 bg-slate-50/30" rows={3} placeholder="Escribir observaciones o comentarios técnicos..." value={comment} onChange={(e) => setComment(e.target.value)} />
                     <div className="flex flex-wrap gap-3">
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-slate-800 text-white rounded-lg hover:bg-slate-900 text-sm font-bold shadow-sm transition-colors"><MessageSquare size={16} className="mr-2" /> Guardar Observación</button>
                        {canRestart && <button onClick={() => handleActionClick('ADVANCE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 text-sm font-bold shadow-sm">Reiniciar Flujo</button>}
                        {canApprove && <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm font-bold shadow-sm"><CheckCircle size={16} className="mr-2" /> Aprobar</button>}
                        {canReject && <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-4 py-2 bg-red-100 text-red-700 hover:bg-red-200 rounded-lg text-sm font-bold border border-red-200"><XCircle size={16} className="mr-2" /> Rechazar</button>}
                     </div>
                </div>
            )}
        </div>

        {/* HISTORIAL COMPLETO - APARIENCIA EXACTA A IMAGEN */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[500px]">
            <h3 className="font-semibold text-slate-800 mb-6 border-b border-slate-100 pb-3">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-12 text-slate-400">
                      <Clock size={40} className="mb-2 opacity-20" />
                      <p className="text-xs">Sin historial.</p>
                  </div>
                ) : (
                  <div className="space-y-8 pl-4 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              {/* Dot Timeline */}
                              <div className="absolute -left-[22px] top-1.5 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm"></div>

                              {/* Timestamp - GRIS SUPERIOR */}
                              <div className="text-[11px] text-slate-400 mb-1">
                                  {formatDate(h.timestamp)}
                              </div>

                              {/* Action and User - NEGRITA */}
                              <div className="text-sm text-slate-700 mb-2">
                                  <span className="font-bold">{h.action}</span>
                                  <span className="mx-1 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-bold text-slate-800">{h.userName}</span>
                              </div>

                              {/* Version Badge - GRIS PILL */}
                              <div className="mb-2">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-bold border border-slate-200">
                                      Versión: {h.version || '-'}
                                  </span>
                              </div>

                              {/* Comment Box - GRIS CLARO CURSIVA */}
                              {h.comment && (
                                  <div className="bg-slate-50 border border-slate-100 rounded-lg p-3 text-xs italic text-slate-600 leading-relaxed shadow-sm">
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-4 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 leading-tight">Este microproceso está en estado <b>Pendiente</b> según matriz.</p>
              </div>
            )}
        </div>
      </div>

      {/* Response Modal */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-bold flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2"><div className="flex items-start gap-3"><Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" /><div><p className="text-xs font-bold text-blue-800 uppercase mb-1">Carga de Documento Requerida</p><p className="text-xs text-blue-900 leading-relaxed font-medium">{getCoordinatorRuleHint(doc.state, pendingAction)}</p></div></div></div>
                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}><input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />{responseFile ? (isFileValid ? <div className="text-green-700 animate-fadeIn"><CheckCircle size={40} className="mx-auto mb-3" /><p className="font-bold text-sm">{responseFile.name}</p><p className="text-[10px] mt-1 font-bold uppercase opacity-60">Versión: {detectedVersion}</p></div> : <div className="text-red-600 animate-fadeIn"><FileX size={40} className="mx-auto mb-3" /><p className="font-bold text-sm">{responseFile.name}</p><div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100"><ul className="list-disc pl-4 space-y-1 font-medium">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul></div></div>) : <div className="text-slate-400 group-hover:text-indigo-600 transition-colors"><Upload size={40} className="mx-auto mb-3 opacity-50" /><p className="font-bold text-sm uppercase tracking-wide">Click para cargar respuesta</p><p className="text-[10px] mt-1 opacity-60">Nomenclatura institucional obligatoria.</p></div>}</div>
                        <div className="flex justify-end gap-3 pt-4 border-t border-slate-50"><button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-bold">Cancelar</button><button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-6 py-2 rounded-lg text-white text-sm font-extrabold shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}><Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}</button></div>
                  </div>
              </div>
          </div>
      )}

      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-slideUp">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between"><h3 className="text-lg font-bold text-red-800 flex items-center gap-2"><Trash2 size={24} /> Confirmar Eliminación</h3><button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600"><XCircle size={20} /></button></div>
                  <div className="p-8"><p className="text-slate-700 mb-6 text-sm">¿Estás seguro de que quieres eliminar permanentemente: <strong>{doc.title}</strong>? Esta acción borrará el registro y su historia.</p><div className="flex justify-end gap-3"><button onClick={() => setShowDeleteModal(false)} className="px-4 py-2 text-slate-600 font-bold text-sm">Cancelar</button><button onClick={async () => { if (!doc) return; setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); }} className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-extrabold text-sm shadow-lg shadow-red-200">Sí, Eliminar Registro</button></div></div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, ArrowRight, History as HistoryIcon, Layers } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Escribe una observación.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Agrega una observación para el rechazo.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      setShowResponseModal(false); 
      await executeTransition(pendingAction, comment, responseFile, detectedVersion);
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const isDocActive = doc.state !== DocState.APPROVED;

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button onClick={() => setShowDeleteModal(true)} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors">
                <Trash2 size={14} className="mr-1.5" /> Eliminar
            </button>
        )}
      </div>

      {/* HEADER CARD */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold uppercase tracking-widest flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName}</p>}</div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Versión Actual</p><p className="font-mono text-slate-800 font-black text-xs">{doc.version}</p></div>
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Progreso</p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Actualizado</p><p className="font-bold text-slate-700">{new Date(doc.updatedAt).toLocaleDateString('es-CL')}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        {/* LEFT COLUMN: ACTIONS */}
        <div className="lg:col-span-2 space-y-6">
            {!canEdit && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                     />

                     <div className="flex flex-wrap gap-3">
                        {/* GUARDAR OBSERVACIÓN - COLOR OSCURO COMO IMAGEN */}
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95">
                            <MessageSquare size={18} className="mr-2" /> Guardar Observación
                        </button>

                        {/* NOTIFICAR ANALISTA - COLOR CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {/* NOTIFICAR COORDINADOR (SI ES ANALISTA) */}
                        {isAnalystAssigned && isDocActive && (
                             <button onClick={handleNotifyCoordinator} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {/* APROBAR - COLOR VERDE COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95">
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {/* RECHAZAR - COLOR ROJO CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95">
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        {/* RIGHT COLUMN: HISTORIAL COMPLETO (APARIENCIA EXACTA) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              {/* Punto en el timeline */}
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>

                              {/* Fecha y Hora (Gris arriba como imagen) */}
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>

                              {/* Acción y Usuario (Negrita como imagen) */}
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>

                              {/* Versión Badge (Pill gris) */}
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {h.version || '-'}
                                  </span>
                              </div>

                              {/* Caja de Comentario (Gris claro cursiva como imagen) */}
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {/* Response Modal */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {detectedVersion}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Modal */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-100">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-black text-red-800 flex items-center gap-2"><Trash2 size={24} /> Eliminar Registro</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center text-red-600 mx-auto mb-4">
                          <AlertTriangle size={32} />
                      </div>
                      <p className="text-slate-700 mb-6 text-sm font-medium leading-relaxed">
                          ¿Está seguro de que desea eliminar permanentemente: <strong>{doc.title}</strong>? Esta acción es irreversible y borrará todo el historial consolidado.
                      </p>
                      <div className="flex justify-center gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-5 py-2 text-slate-500 hover:text-slate-800 text-sm font-bold uppercase tracking-tighter">Cancelar</button>
                          <button onClick={async () => { if (!doc) return; setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); }} className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-black text-sm shadow-lg shadow-red-100 transition-all active:scale-95">Eliminar Definitivamente</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
// Fixed: Added AlertTriangle to imports from lucide-react
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, ArrowRight, History as HistoryIcon, Layers, AlertTriangle } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Escribe una observación.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Agrega una observación para el rechazo.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      setShowResponseModal(false); 
      await executeTransition(pendingAction, comment, responseFile, detectedVersion);
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const isDocActive = doc.state !== DocState.APPROVED;

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button onClick={() => setShowDeleteModal(true)} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors">
                <Trash2 size={14} className="mr-1.5" /> Eliminar
            </button>
        )}
      </div>

      {/* HEADER CARD */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold uppercase tracking-widest flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName}</p>}</div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Versión Actual</p><p className="font-mono text-slate-800 font-black text-xs">{doc.version}</p></div>
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Progreso</p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Actualizado</p><p className="font-bold text-slate-700">{new Date(doc.updatedAt).toLocaleDateString('es-CL')}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        {/* LEFT COLUMN: ACTIONS */}
        <div className="lg:col-span-2 space-y-6">
            {!canEdit && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                     />

                     <div className="flex flex-wrap gap-3">
                        {/* GUARDAR OBSERVACIÓN - COLOR OSCURO COMO IMAGEN */}
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95">
                            <MessageSquare size={18} className="mr-2" /> Guardar Observación
                        </button>

                        {/* NOTIFICAR ANALISTA - COLOR CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {/* NOTIFICAR COORDINADOR (SI ES ANALISTA) */}
                        {isAnalystAssigned && isDocActive && (
                             <button onClick={handleNotifyCoordinator} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {/* APROBAR - COLOR VERDE COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95">
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {/* RECHAZAR - COLOR ROJO CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95">
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        {/* RIGHT COLUMN: HISTORIAL COMPLETO (APARIENCIA EXACTA) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              {/* Punto en el timeline */}
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>

                              {/* Fecha y Hora (Gris arriba como imagen) */}
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>

                              {/* Acción y Usuario (Negrita como imagen) */}
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>

                              {/* Versión Badge (Pill gris) */}
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {h.version || '-'}
                                  </span>
                              </div>

                              {/* Caja de Comentario (Gris claro cursiva como imagen) */}
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {/* Response Modal */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {detectedVersion}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Modal */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-100">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-black text-red-800 flex items-center gap-2"><Trash2 size={24} /> Eliminar Registro</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center text-red-600 mx-auto mb-4">
                          <AlertTriangle size={32} />
                      </div>
                      <p className="text-slate-700 mb-6 text-sm font-medium leading-relaxed">
                          ¿Está seguro de que desea eliminar permanentemente: <strong>{doc.title}</strong>? Esta acción es irreversible y borrará todo el historial consolidado.
                      </p>
                      <div className="flex justify-center gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-5 py-2 text-slate-500 hover:text-slate-800 text-sm font-bold uppercase tracking-tighter">Cancelar</button>
                          <button onClick={async () => { if (!doc) return; setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); }} className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-black text-sm shadow-lg shadow-red-100 transition-all active:scale-95">Eliminar Definitivamente</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
// Fixed: Added AlertTriangle to imports from lucide-react
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, Users, ArrowRight, History as HistoryIcon, Layers, AlertTriangle } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyReferent = () => {
      if (!doc || referentEmails.length === 0) {
          alert("No hay correos de referentes vinculados a este proceso en la matriz.");
          return;
      }
      const subject = encodeURIComponent(`Revisión Técnica: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimados Referentes,\nSe solicita su validación para el documento: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nLink de revisión: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Escribe una observación.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Agrega una observación para el rechazo.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      setShowResponseModal(false); 
      await executeTransition(pendingAction, comment, responseFile, detectedVersion);
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const isDocActive = doc.state !== DocState.APPROVED;

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button onClick={() => setShowDeleteModal(true)} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors">
                <Trash2 size={14} className="mr-1.5" /> Eliminar
            </button>
        )}
      </div>

      {/* HEADER CARD */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold uppercase tracking-widest flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName}</p>}</div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Versión Actual</p><p className="font-mono text-slate-800 font-black text-xs">{doc.version}</p></div>
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Progreso</p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Actualizado</p><p className="font-bold text-slate-700">{new Date(doc.updatedAt).toLocaleDateString('es-CL')}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        {/* LEFT COLUMN: ACTIONS */}
        <div className="lg:col-span-2 space-y-6">
            {!canEdit && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                     />

                     <div className="flex flex-wrap gap-3">
                        {/* GUARDAR OBSERVACIÓN - COLOR OSCURO COMO IMAGEN */}
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95">
                            <MessageSquare size={18} className="mr-2" /> Guardar Observación
                        </button>

                        {/* NOTIFICAR ANALISTA - COLOR CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {/* NOTIFICAR REFERENTE (SI ES COORDINADOR Y HAY REFERENTES) */}
                        {isCoordinatorOrAdmin && referentEmails.length > 0 && [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) && (
                            <button onClick={handleNotifyReferent} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Users size={18} className="mr-2 text-indigo-500" /> Notificar Referente
                            </button>
                        )}

                        {/* NOTIFICAR COORDINADOR (SI ES ANALISTA) */}
                        {isAnalystAssigned && isDocActive && (
                             <button onClick={handleNotifyCoordinator} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {/* APROBAR - COLOR VERDE COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95">
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {/* RECHAZAR - COLOR ROJO CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95">
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        {/* RIGHT COLUMN: HISTORIAL COMPLETO (APARIENCIA EXACTA) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              {/* Punto en el timeline */}
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>

                              {/* Fecha y Hora (Gris arriba como imagen) */}
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>

                              {/* Acción y Usuario (Negrita como imagen) */}
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>

                              {/* Versión Badge (Pill gris) */}
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {h.version || '-'}
                                  </span>
                              </div>

                              {/* Caja de Comentario (Gris claro cursiva como imagen) */}
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {/* Response Modal */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {detectedVersion}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Modal */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-100">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-black text-red-800 flex items-center gap-2"><Trash2 size={24} /> Eliminar Registro</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center text-red-600 mx-auto mb-4">
                          <AlertTriangle size={32} />
                      </div>
                      <p className="text-slate-700 mb-6 text-sm font-medium leading-relaxed">
                          ¿Está seguro de que desea eliminar permanentemente: <strong>{doc.title}</strong>? Esta acción es irreversible y borrará todo el historial consolidado.
                      </p>
                      <div className="flex justify-center gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-5 py-2 text-slate-500 hover:text-slate-800 text-sm font-bold uppercase tracking-tighter">Cancelar</button>
                          <button onClick={async () => { if (!doc) return; setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); }} className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-black text-sm shadow-lg shadow-red-100 transition-all active:scale-95">Eliminar Definitivamente</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
// Fixed: Added AlertTriangle to imports from lucide-react
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, Users, ArrowRight, History as HistoryIcon, Layers, AlertTriangle } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referents);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) resolvedReferentEmails = allReferents.filter(r => node.referentIds.includes(r.id)).map(r => r.email);
      }
      return { assignees: resolvedAssigneeIds, referents: resolvedReferentEmails };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyReferent = () => {
      if (!doc || referentEmails.length === 0) {
          alert("No hay correos de referentes vinculados a este proceso en la matriz.");
          return;
      }
      const subject = encodeURIComponent(`Revisión Técnica: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      // Actualizado: Se remueve el link de acceso a petición del usuario
      const body = encodeURIComponent(`Estimados Referentes,\nSe solicita su validación para el documento: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nQuedamos atentos a sus observaciones.\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Escribe una observación.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Agrega una observación para el rechazo.'); return; }
          setPendingAction(action); setResponseFile(null); setFileError([]); setIsFileValid(false); setDetectedVersion(''); setShowResponseModal(true);
      }
  };

  const handleResponseFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files[0] && doc && pendingAction) {
          const f = e.target.files[0]; setResponseFile(f);
          const result = parseDocumentFilename(f.name, doc.project, doc.microprocess, doc.docType);
          if (!result.valido) { setFileError(result.errores); setIsFileValid(false); return; }
          const rules = validateCoordinatorRules(f.name, doc.version, doc.state, pendingAction);
          if (!rules.valid) { setFileError([rules.error || 'Error de validación.']); setIsFileValid(false); return; }
          setIsFileValid(true); setFileError([]); setDetectedVersion(result.nomenclatura || '');
      }
  };

  const handleSubmitResponse = async () => {
      if (!doc || !pendingAction || !responseFile || !isFileValid) return;
      setShowResponseModal(false); 
      await executeTransition(pendingAction, comment, responseFile, detectedVersion);
  };

  const executeTransition = async (action: any, transitionComment: string, file?: File, customVersion?: string) => {
      if (!doc) return; setActionLoading(true);
      try {
        await DocumentService.transitionState(doc.id, user, action, transitionComment || `Gestión realizada.`, file || undefined, customVersion || undefined);
        setComment(''); await loadData(doc.id);
      } catch (err: any) { alert('Error: ' + err.message); } finally { setActionLoading(false); }
  };

  const formatDate = (isoString: string) => {
    const date = new Date(isoString);
    if (isNaN(date.getTime())) return 'Fecha no disponible';
    return date.toLocaleString('es-CL', { 
        day: '2-digit', month: '2-digit', year: 'numeric', 
        hour: '2-digit', minute: '2-digit', second: '2-digit',
        hour12: true 
    });
  };

  if (loading) return <div className="p-8 text-center text-slate-500">Cargando documento...</div>;
  if (!doc) return <div className="p-12 text-center text-slate-500">No se encontró el documento.</div>;

  const config = STATE_CONFIG[doc.state];
  const isAssignee = doc.assignees && doc.assignees.includes(user.id);
  const isAuthor = doc.authorId === user.id;
  const isAnalystAssigned = user.role === UserRole.ANALYST && (isAssignee || isAuthor);
  const isCoordinatorOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
  const canEdit = isAnalystAssigned || isCoordinatorOrAdmin;
  const isDocActive = doc.state !== DocState.APPROVED;

  return (
    <div className="max-w-6xl mx-auto space-y-6 pb-12">
      <div className="flex justify-between items-center">
        <button onClick={() => navigate(-1)} className="flex items-center text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors">
            <ArrowLeft size={16} className="mr-1" /> Volver
        </button>
        {user.role === UserRole.ADMIN && !doc.id.startsWith('virtual-') && (
            <button onClick={() => setShowDeleteModal(true)} className="flex items-center text-red-500 hover:text-red-700 text-[11px] font-bold uppercase tracking-wider px-3 py-1.5 bg-red-50 hover:bg-red-100 rounded-lg border border-red-100 transition-colors">
                <Trash2 size={14} className="mr-1.5" /> Eliminar
            </button>
        )}
      </div>

      {/* HEADER CARD */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
        <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-6">
            <div>
                <div className="flex items-center gap-2 mb-2">
                    {doc.project && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-slate-800 text-white tracking-wider">{doc.project}</span>}
                    {doc.docType && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-indigo-100 text-indigo-700 border border-indigo-200 tracking-wider">{doc.docType}</span>}
                    {doc.hasPendingRequest && <span className="px-2 py-0.5 rounded text-[10px] font-bold uppercase bg-blue-500 text-white animate-pulse tracking-wider">Solicitud Pendiente</span>}
                </div>
                <h1 className="text-2xl font-black text-slate-900 leading-tight">{doc.title}</h1>
                <p className="text-slate-500 text-sm font-medium mt-1">{doc.description}</p>
            </div>
            <div className={`px-3 py-2 rounded-lg text-xs font-bold uppercase tracking-widest flex items-center self-start border shadow-sm ${config.color}`}>
                <Activity size={14} className="mr-2" />{config.label}
            </div>
        </div>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-[11px] border-t border-slate-100 pt-5">
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Analistas</p>{assigneeNames.length > 0 ? assigneeNames.map((name, i) => <p key={i} className="font-bold text-slate-700">{name}</p>) : <p className="font-bold text-slate-700">{doc.authorName}</p>}</div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Versión Actual</p><p className="font-mono text-slate-800 font-black text-xs">{doc.version}</p></div>
            <div>
                <p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Progreso</p>
                <div className="flex items-center gap-2">
                    <div className="flex-1 bg-slate-100 rounded-full h-2 min-w-[80px] overflow-hidden border border-slate-200">
                        <div className="bg-indigo-600 h-full rounded-full shadow-[0_0_8px_rgba(79,70,229,0.3)] transition-all duration-500" style={{ width: `${config.progress}%` }}></div>
                    </div>
                    <span className="font-black text-slate-800">{config.progress}%</span>
                </div>
            </div>
            <div><p className="text-slate-400 uppercase font-bold tracking-widest mb-1.5">Actualizado</p><p className="font-bold text-slate-700">{new Date(doc.updatedAt).toLocaleDateString('es-CL')}</p></div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 items-start">
        {/* LEFT COLUMN: ACTIONS */}
        <div className="lg:col-span-2 space-y-6">
            {!canEdit && <div className="bg-amber-50 border-l-4 border-amber-400 p-4 flex gap-3 text-xs text-amber-800 font-medium"><Lock size={18} className="text-amber-500" /> Vista de solo lectura. No tiene permisos de gestión en este documento.</div>}

            {canEdit && (
                <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                     <h3 className="font-bold text-slate-800 mb-5 flex items-center gap-2 uppercase text-[11px] tracking-widest">
                        Acciones de Flujo
                     </h3>

                     <textarea 
                        className="w-full p-4 border border-slate-200 rounded-xl text-sm mb-5 outline-none focus:ring-4 focus:ring-indigo-500/5 focus:border-indigo-500 bg-slate-50/30 transition-all placeholder:text-slate-400" 
                        rows={4} 
                        placeholder="Escriba aquí sus observaciones o comentarios técnicos..." 
                        value={comment} 
                        onChange={(e) => setComment(e.target.value)} 
                     />

                     <div className="flex flex-wrap gap-3">
                        {/* GUARDAR OBSERVACIÓN - COLOR OSCURO COMO IMAGEN */}
                        <button onClick={() => handleActionClick('COMMENT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-[#1e293b] text-white rounded-lg hover:bg-slate-800 text-sm font-bold shadow-sm transition-all active:scale-95">
                            <MessageSquare size={18} className="mr-2" /> Guardar Observación
                        </button>

                        {/* NOTIFICAR ANALISTA - COLOR CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && (
                            <button onClick={handleNotifyAnalyst} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Analista
                            </button>
                        )}

                        {/* NOTIFICAR REFERENTE (SI ES COORDINADOR Y HAY REFERENTES) */}
                        {isCoordinatorOrAdmin && referentEmails.length > 0 && [DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(doc.state) && (
                            <button onClick={handleNotifyReferent} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Users size={18} className="mr-2 text-indigo-500" /> Notificar Referente
                            </button>
                        )}

                        {/* NOTIFICAR COORDINADOR (SI ES ANALISTA) */}
                        {isAnalystAssigned && isDocActive && (
                             <button onClick={handleNotifyCoordinator} className="flex items-center px-5 py-2.5 bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 rounded-lg text-sm font-bold shadow-sm transition-all active:scale-95">
                                <Mail size={18} className="mr-2 text-indigo-500" /> Notificar Coordinador
                            </button>
                        )}

                        {/* APROBAR - COLOR VERDE COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('APPROVE')} disabled={actionLoading} className="flex items-center px-6 py-2.5 bg-[#22c55e] text-white rounded-lg hover:bg-green-600 text-sm font-bold shadow-md shadow-green-100 transition-all active:scale-95">
                                <CheckCircle size={18} className="mr-2" /> Aprobar
                            </button>
                        )}

                        {/* RECHAZAR - COLOR ROJO CLARO COMO IMAGEN */}
                        {isCoordinatorOrAdmin && isDocActive && (
                            <button onClick={() => handleActionClick('REJECT')} disabled={actionLoading} className="flex items-center px-5 py-2.5 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg text-sm font-bold border border-red-100 transition-all active:scale-95">
                                <XCircle size={18} className="mr-2" /> Rechazar
                            </button>
                        )}
                     </div>
                </div>
            )}
        </div>

        {/* RIGHT COLUMN: HISTORIAL COMPLETO (APARIENCIA EXACTA) */}
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-col min-h-[550px]">
            <h3 className="font-bold text-slate-800 mb-6 border-b border-slate-100 pb-4 text-sm">Historial Completo</h3>

            <div className="flex-1 overflow-y-auto pr-3 custom-scrollbar">
                {history.length === 0 ? (
                  <div className="flex flex-col items-center justify-center py-16 text-slate-300">
                      <Clock size={40} className="mb-3 opacity-20" />
                      <p className="text-xs font-bold uppercase tracking-widest">Sin registros</p>
                  </div>
                ) : (
                  <div className="space-y-10 pl-5 border-l-[1.5px] border-slate-100 relative ml-2">
                      {history.map((h) => (
                          <div key={h.id} className="relative group animate-fadeIn">
                              {/* Punto en el timeline */}
                              <div className="absolute -left-[23px] top-2 h-3 w-3 rounded-full bg-slate-300 border-2 border-white shadow-sm ring-4 ring-white group-hover:bg-indigo-500 transition-colors"></div>

                              {/* Fecha y Hora (Gris arriba como imagen) */}
                              <div className="text-[11px] font-bold text-slate-400 mb-1 flex items-center gap-1.5 uppercase tracking-tighter">
                                  {formatDate(h.timestamp)}
                              </div>

                              {/* Acción y Usuario (Negrita como imagen) */}
                              <div className="text-[13px] text-slate-700 mb-2">
                                  <span className="font-black text-slate-900">{h.action}</span>
                                  <span className="mx-1.5 font-medium text-slate-400 text-xs">por</span>
                                  <span className="font-black text-slate-800">{h.userName}</span>
                              </div>

                              {/* Versión Badge (Pill gris) */}
                              <div className="mb-2.5">
                                  <span className="inline-block px-2 py-0.5 rounded bg-slate-100 text-slate-500 text-[10px] font-black border border-slate-200 uppercase tracking-tighter">
                                      Versión: {h.version || '-'}
                                  </span>
                              </div>

                              {/* Caja de Comentario (Gris claro cursiva como imagen) */}
                              {h.comment && (
                                  <div className="bg-slate-50/80 border border-slate-100 rounded-lg p-3.5 text-xs italic text-slate-600 leading-relaxed shadow-sm relative overflow-hidden">
                                      <div className="absolute top-0 left-0 w-1 h-full bg-slate-200/50"></div>
                                      "{h.comment}"
                                  </div>
                              )}
                          </div>
                      ))}
                  </div>
                )}
            </div>

            {doc.id.startsWith('virtual-') && (
              <div className="mt-6 p-4 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-3 shadow-sm">
                  <Info className="text-amber-600 flex-shrink-0" size={18} />
                  <p className="text-xs text-amber-800 font-bold leading-tight">Este microproceso aún no posee documentos cargados (Estado Pendiente).</p>
              </div>
            )}
        </div>
      </div>

      {/* Response Modal */}
      {showResponseModal && pendingAction && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg overflow-hidden border border-slate-100">
                  <div className={`p-5 border-b border-slate-100 flex justify-between items-center ${pendingAction === 'APPROVE' ? 'bg-green-50' : 'bg-red-50'}`}>
                      <h3 className={`text-lg font-black flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'text-green-800' : 'text-red-800'}`}>{pendingAction === 'APPROVE' ? <CheckCircle size={24} /> : <XCircle size={24} />}{pendingAction === 'APPROVE' ? 'Aprobar Solicitud' : 'Rechazar Solicitud'}</h3>
                      <button onClick={() => setShowResponseModal(false)} className="text-slate-400 hover:text-slate-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-6 space-y-4">
                        <div className="p-4 bg-blue-50 border border-blue-100 rounded-xl flex flex-col gap-2">
                            <div className="flex items-start gap-3">
                                <Info size={20} className="text-blue-600 mt-0.5 flex-shrink-0" />
                                <div>
                                    <p className="text-xs font-black text-blue-800 uppercase mb-1">Carga de Documento Requerida</p>
                                    <p className="text-xs text-blue-900 leading-relaxed font-bold">{getCoordinatorRuleHint(doc.state, pendingAction)}</p>
                                </div>
                            </div>
                        </div>

                        <div className={`border-2 border-dashed rounded-2xl p-8 transition-all flex flex-col items-center justify-center text-center group relative ${isFileValid ? 'border-green-400 bg-green-50/50' : fileError.length > 0 ? 'border-red-400 bg-red-50/50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'}`}>
                            <input type="file" ref={fileInputRef} onChange={handleResponseFileSelect} className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" />
                            {responseFile ? (
                                isFileValid ? (
                                    <div className="text-green-700 animate-fadeIn">
                                        <CheckCircle size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <p className="text-[10px] mt-1 font-black uppercase opacity-60">Versión Detectada: {detectedVersion}</p>
                                    </div>
                                ) : (
                                    <div className="text-red-600 animate-fadeIn">
                                        <FileX size={40} className="mx-auto mb-3" />
                                        <p className="font-black text-sm">{responseFile.name}</p>
                                        <div className="mt-3 text-xs text-left bg-white p-2 rounded-lg border border-red-100">
                                            <ul className="list-disc pl-4 space-y-1 font-bold">{fileError.map((err, idx) => <li key={idx}>{err}</li>)}</ul>
                                        </div>
                                    </div>
                                )
                            ) : (
                                <div className="text-slate-400 group-hover:text-indigo-600 transition-colors">
                                    <Upload size={40} className="mx-auto mb-3 opacity-50" />
                                    <p className="font-black text-sm uppercase tracking-wider">Haga clic para cargar respuesta</p>
                                    <p className="text-[10px] mt-1 opacity-60 font-bold">Nomenclatura institucional obligatoria.</p>
                                </div>
                            )}
                        </div>

                        <div className="flex justify-end gap-3 pt-4">
                            <button onClick={() => setShowResponseModal(false)} className="px-4 py-2 text-slate-500 hover:text-slate-800 text-sm font-black uppercase tracking-tighter transition-colors">Cancelar</button>
                            <button onClick={handleSubmitResponse} disabled={!isFileValid} className={`px-6 py-2 rounded-lg text-white text-sm font-black shadow-md transition-all flex items-center gap-2 ${pendingAction === 'APPROVE' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'} disabled:opacity-50 disabled:grayscale`}>
                                <Save size={16} />Confirmar {pendingAction === 'APPROVE' ? 'Aprobación' : 'Rechazo'}
                            </button>
                        </div>
                  </div>
              </div>
          </div>
      )}

      {/* Delete Modal */}
      {showDeleteModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-fadeIn">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden border border-slate-100">
                  <div className="p-5 border-b border-red-100 bg-red-50 flex items-center justify-between">
                      <h3 className="text-lg font-black text-red-800 flex items-center gap-2"><Trash2 size={24} /> Eliminar Registro</h3>
                      <button onClick={() => setShowDeleteModal(false)} className="text-red-400 hover:text-red-600 transition-colors"><XCircle size={20} /></button>
                  </div>
                  <div className="p-8 text-center">
                      <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center text-red-600 mx-auto mb-4">
                          <AlertTriangle size={32} />
                      </div>
                      <p className="text-slate-700 mb-6 text-sm font-medium leading-relaxed">
                          ¿Está seguro de que desea eliminar permanentemente: <strong>{doc.title}</strong>? Esta acción es irreversible y borrará todo el historial consolidado.
                      </p>
                      <div className="flex justify-center gap-3">
                          <button onClick={() => setShowDeleteModal(false)} className="px-5 py-2 text-slate-500 hover:text-slate-800 text-sm font-bold uppercase tracking-tighter">Cancelar</button>
                          <button onClick={async () => { if (!doc) return; setShowDeleteModal(false); setLoading(true); await DocumentService.delete(doc.id); navigate('/', { replace: true }); }} className="px-6 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-black text-sm shadow-lg shadow-red-100 transition-all active:scale-95">Eliminar Definitivamente</button>
                      </div>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

export default DocumentDetail;

import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import { DocumentService, HistoryService, UserService, HierarchyService, ReferentService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocHistory, UserRole, DocState, FullHierarchy, Referent } from '../types';
import { STATE_CONFIG } from '../constants';
import { parseDocumentFilename, validateCoordinatorRules, getCoordinatorRuleHint } from '../utils/filenameParser';
// Fixed: Added AlertTriangle to imports from lucide-react
import { ArrowLeft, FileText, CheckCircle, XCircle, Activity, Paperclip, Mail, MessageSquare, Send, FileCheck, FileX, Info, ListFilter, Trash2, Lock, Save, PlusCircle, Calendar, Upload, ExternalLink, Clock, User as UserIcon, Users, ArrowRight, History as HistoryIcon, Layers, AlertTriangle } from 'lucide-react';

interface Props {
  user: User;
}

const DocumentDetail: React.FC<Props> = ({ user }) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation(); 

  const [doc, setDoc] = useState<Document | null>(null);
  const [history, setHistory] = useState<DocHistory[]>([]);
  const [assigneeNames, setAssigneeNames] = useState<string[]>([]);
  const [assigneeEmails, setAssigneeEmails] = useState<string[]>([]);
  const [referentEmails, setReferentEmails] = useState<string[]>([]);
  const [referentNames, setReferentNames] = useState<string[]>([]);
  const [coordinatorEmail, setCoordinatorEmail] = useState<string>('');
  const [authorEmail, setAuthorEmail] = useState<string>('');
  const [loading, setLoading] = useState(true);
  const [comment, setComment] = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  const [showResponseModal, setShowResponseModal] = useState(false);
  const [pendingAction, setPendingAction] = useState<'APPROVE' | 'REJECT' | null>(null);
  const [responseFile, setResponseFile] = useState<File | null>(null);
  const [fileError, setFileError] = useState<string[]>([]);
  const [isFileValid, setIsFileValid] = useState(false);
  const [detectedVersion, setDetectedVersion] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);

  useEffect(() => {
    if (location.state?.docData) {
        const passedDoc = location.state.docData;
        setDoc(passedDoc);
        if (!passedDoc.id.startsWith('virtual-')) {
             loadAuxiliaryData(passedDoc.id, passedDoc);
        } else {
             setLoading(false);
             if (passedDoc.assignees && passedDoc.assignees.length > 0) {
                 UserService.getAll().then(users => {
                     const names = passedDoc.assignees.map((aid: string) => users.find(u => u.id === aid)?.name).filter((n: string | undefined) => n) as string[];
                     setAssigneeNames(names);
                 });
             }
        }
    } else if (id && !id.startsWith('virtual-')) {
        loadData(id);
    } else {
        setLoading(false);
    }
  }, [id, location.state]);

  const loadAuxiliaryData = async (docId: string, currentDoc: Document) => {
      try {
          const relatedIds = await DocumentService.getRelatedDocIds(
              currentDoc.project!, 
              currentDoc.microprocess || currentDoc.title.split(' - ')[0], 
              currentDoc.docType!
          );

          const [h, allUsers, hierarchy, allReferents] = await Promise.all([
              HistoryService.getHistory(relatedIds),
              UserService.getAll(),
              HierarchyService.getFullHierarchy(),
              ReferentService.getAll()
          ]);

          setHistory(h);
          const coordinator = allUsers.find(u => ['COORDINATOR', 'COORDINADOR', 'ADMIN'].includes((u.role || '').toString().toUpperCase()));
          if (coordinator) setCoordinatorEmail(coordinator.email);
          const author = allUsers.find(u => u.id === currentDoc.authorId);
          if (author) setAuthorEmail(author.email);

          const matrix = resolveMatrixData(currentDoc, hierarchy, allReferents);
          setReferentEmails(matrix.referentEmails);
          setReferentNames(matrix.referentNames);

          if (matrix.assignees.length > 0) {
              const names = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.name).filter(n => n) as string[];
              setAssigneeNames(names);
              const emails = matrix.assignees.map(aid => allUsers.find(u => u.id === aid)?.email).filter(e => e) as string[];
              setAssigneeEmails(emails);
          }
          setLoading(false);
      } catch (e) {
          console.error("Error loading aux data", e);
          setLoading(false);
      }
  };

  const resolveMatrixData = (d: Document, hierarchy: FullHierarchy, allReferents: Referent[]) => {
      let resolvedAssigneeIds = d.assignees || [];
      let resolvedReferentEmails: string[] = [];
      let resolvedReferentNames: string[] = [];

      if (d.project && d.microprocess) {
           const targetMicro = normalizeHeader(d.microprocess);
           const targetProject = normalizeHeader(d.project);
           let node: any = null;
           for (const projKey of Object.keys(hierarchy)) {
               if (normalizeHeader(projKey) === targetProject) {
                   for (const macroKey of Object.keys(hierarchy[projKey])) {
                       for (const procKey of Object.keys(hierarchy[projKey][macroKey])) {
                           const found = hierarchy[projKey][macroKey][procKey].find(n => normalizeHeader(n.name) === targetMicro);
                           if (found) { node = found; break; }
                       }
                       if (node) break;
                   }
               }
               if (node) break;
           }
           if (node?.assignees && (resolvedAssigneeIds.length === 0 || d.authorName.includes('Sistema'))) resolvedAssigneeIds = node.assignees;
           if (node?.referentIds && node.referentIds.length > 0) {
               const matches = allReferents.filter(r => node.referentIds.includes(r.id));
               resolvedReferentEmails = matches.map(r => r.email);
               resolvedReferentNames = matches.map(r => r.name);
           }
      }
      return { assignees: resolvedAssigneeIds, referentEmails: resolvedReferentEmails, referentNames: resolvedReferentNames };
  };

  const loadData = async (docId: string) => {
    setLoading(true);
    try {
        const d = await DocumentService.getById(docId);
        if (d) {
            setDoc(d);
            await loadAuxiliaryData(docId, d);
        } else {
            setDoc(null);
            setLoading(false);
        }
    } catch (error) {
        console.error("Error loading document data:", error);
        setDoc(null);
        setLoading(false);
    }
  };

  const getDocLink = () => `${window.location.origin}/#/doc/${doc?.id}`;

  const handleNotifyAnalyst = () => {
      if (!doc || assigneeEmails.length === 0) {
          alert("No hay correos de analistas definidos para este proceso.");
          return;
      }
      const subject = encodeURIComponent(`Respuesta Solicitud: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      const body = encodeURIComponent(`Estimada/o,\nAdjunto el Informe: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nEstado Actual: ${STATE_CONFIG[doc.state].label}\n\nPuede revisar el detalle y los comentarios en: ${getDocLink()}\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(assigneeEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyReferent = () => {
      if (!doc || referentEmails.length === 0) {
          alert("No hay correos de referentes vinculados a este proceso en la matriz.");
          return;
      }
      const subject = encodeURIComponent(`Revisión Técnica: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
      // Actualizado: Salutación personalizada según solicitud del usuario
      const greeting = referentNames.length > 0 ? `Estimada/o ${referentNames.join(', ')}` : 'Estimados Referentes';
      const body = encodeURIComponent(`${greeting},\n\nSe solicita su validación para el documento: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}\n\nQuedamos atentos a sus observaciones.\n\nSaludos\n${user.name}`);
      window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${encodeURIComponent(referentEmails.join(','))}&su=${subject}&body=${body}`, '_blank');
  };

  const handleNotifyCoordinator = () => {
    if (!doc || !coordinatorEmail) { alert(`Aviso: No se ha detectado correo del coordinador.`); return; }
    const subject = encodeURIComponent(`Solicitud de Revisión: ${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}`);
    const body = encodeURIComponent(`Estimado,\nPara su revisión, he cargado el documento "${doc.project} - ${doc.microprocess} - ${doc.docType || ''} - ${doc.version}",\n\nLink: ${getDocLink()}\n\nSaludos\n${user.name}`);
    window.open(`https://mail.google.com/mail/?view=cm&fs=1&to=${coordinatorEmail}&su=${subject}&body=${body}`, '_blank');
  };

  const handleActionClick = async (action: 'ADVANCE' | 'APPROVE' | 'REJECT' | 'COMMENT') => {
      if (!doc) return;
      if (action === 'COMMENT') { if (!comment.trim()) { alert('Escribe una observación.'); return; } executeTransition('COMMENT', comment); return; }
      if (action === 'ADVANCE') { executeTransition('ADVANCE', ''); return; }
      if (action === 'APPROVE' || action === 'REJECT') {
          if (action === 'REJECT' && !comment) { alert('Agrega una observación para el rechazo.'); return; }
